(* ========================================================================= *)
(* SHA-512 block compression, scalar (no SHA-NI / no SIMD) x86 version.      *)
(*                                                                           *)
(* The code is emitted by the Ragamuffin transpiler; it computes the FIPS    *)
(* 180-4 SHA-512 compression function over num_blocks 128-byte big-endian    *)
(* message blocks, updating the 8-word (64-bit) state in place:              *)
(*                                                                           *)
(* extern void sha512_compress                                               *)
(*   (uint64_t state[static 8], const uint8_t *data, size_t num_blocks);     *)
(*                                                                           *)
(* SysV: RDI = state, RSI = data, RDX = num_blocks (must be nonzero).        *)
(*                                                                           *)
(* The K512 round-constant table lives in .rodata and is addressed           *)
(* RIP-relatively (leaq K512(%rip),%rbp), so the code is frozen with         *)
(* define_assert_relocs_from_elf. K512 holds the 80 round constants with     *)
(* each 16-byte row doubled (80*16 = 1280 bytes), followed by one further    *)
(* doubled 16-byte byteswap-mask row (32 bytes), total 1312 bytes. The top   *)
(* byte (+7) of the K-word the loop is about to consume is the sentinel that *)
(* terminates the 16-round inner body (cmp BYTE PTR [rbp+7],0; jnz) after    *)
(* exactly 4 iterations.                                                     *)
(* ========================================================================= *)

needs "x86/proofs/base.ml";;
needs "x86/proofs/consttime.ml";;
needs "x86/proofs/utils/sha512_spec.ml";;
needs "x86/proofs/utils/sha512_bridge.ml";;

(* ------------------------------------------------------------------------- *)
(* The machine code, with the K512 table relocation abstracted.              *)
(*                                                                           *)
(* Regenerate the assertion skeleton below with:                             *)
(*                                                                           *)
(* print_literal_relocs_from_elf                                             *)
(*   ~map_symbol_name:(function "WHOLE_READONLY" -> "K512"                    *)
(*                            | s -> "unused_" ^ s)                           *)
(*   "x86/sha512/sha512_compress.o";;                                        *)
(*                                                                           *)
(* (K512 is a local symbol, so the relocation in .rela.text is against the   *)
(* .rodata section symbol; since K512 is the whole .rodata section, we name  *)
(* the WHOLE_READONLY blob "K512" and the redundant per-symbol copy          *)
(* "unused_K512", mirroring the x86/tutorial/rodata_local.S example.)        *)
(* ------------------------------------------------------------------------- *)

