(* The byte-list definition of the K512 table: |- K512 = [...] (1312 bytes). *)

let K512_DATA =
  List.find (fun th -> name_of(lhs(concl th)) = "K512") rodata_constants_data;;

let sha512_compress_tmc =
  define_trimmed "sha512_compress_tmc"
                 sha512_compress_mc;;

(* X86_MK_EXEC_RULE rather than X86_MK_CORE_EXEC_RULE: the CORE variant's
   BUTLAST step (X86_TRIM_EXEC_RULE) fails (AP_TERM) on an mc theorem that is
   quantified over pc and rodata symbols, and the in-repo reloc precedent
   (curve25519_x25519base.ml) likewise uses X86_MK_EXEC_RULE on the tmc. *)

let SHA512_COMPRESS_EXEC =
  X86_MK_EXEC_RULE sha512_compress_tmc;;

(* ------------------------------------------------------------------------- *)
(* Phase 4 - one compression head round, register-only.                      *)
(*                                                                           *)
(* The smallest meaningful unit: ONE SHA-512 head round of the frozen code   *)
(* computes sha512_round on the eight 64-bit working-variable registers,     *)
(* plus the W-ring memory path (the big-endian load "mov (%rsi),%r12 ;       *)
(* bswap %r12" producing word_bytereverse wraw from the raw little-endian    *)
(* quadword wraw at (%rsi), and its store "mov %r12,(%rsp)" into W-ring slot  *)
(* stackptr+0).  This validates symbolic stepping + the Phase-3 bridges at    *)
(* ~3-round scale; it is the int64 analogue of SHA-256's                     *)
(* SHA256_BLOCK_NOHW_ROUND0 (ragamuffin_sha256_x86_nohw).                    *)
(*                                                                           *)
(* Entry/exit (decoded from objdump of x86/sha512/sha512_compress.o; the     *)
(* tmc offset is the orig .o offset minus 4 for the trimmed ENDBR64):        *)
(*  - The round-0 body runs from orig 0x65 (the loop top "mov %rbx,%rdi")    *)
(*    to orig 0xdb (the round-1 W-load "mov 0x8(%rsi),%r12").                 *)
(*  - We ENTER at orig 0x6f = tmc pc+0x6b ("xor %rcx,%rdi", i.e. just AFTER   *)
(*    "mov %rbx,%rdi" (rdi := b) and the RIP-relative "lea K512(%rip),%rbp"   *)
(*    (whose post-state RBP carries reloc arithmetic that is a Phase-6        *)
(*    concern).  So the precondition supplies RBP = kbase (the abstract       *)
(*    K-table cursor), RDI = b directly, and reads the round constant k       *)
(*    symbolically from (memory :> bytes64 kbase).                           *)
(*  - 33 instructions, pc+0x6b .. pc+0xd7.                                    *)
(*                                                                           *)
(* This Ragamuffin code does NOT defer the Sigma0/T2 add: "add %r14,%r11"    *)
(* (Sigma0 fold completing new-a) at orig 0xd8 = pc+0xd4 is the LAST         *)
(* instruction of round 0, before round 1's W-load.  Each round fully        *)
(* computes its 8 outputs in place (register-ROLE ROTATION, not deferred     *)
(* adds), so the round lemma maps to sha512_round with NO one-round offset.   *)
(*                                                                           *)
(* Output register -> sha512_round element map (all int64):                  *)
(*   R11=EL 0 (new a),  RAX=EL 1 (=a),   RBX=EL 2 (=b),   RCX=EL 3 (=c),     *)
(*   RDX=EL 4 (new e),  R8 =EL 5 (=e),   R9 =EL 6 (=f),   R10=EL 7 (=g).     *)
(* The round's message word is word_bytereverse wraw (the big-endian         *)
(* assembly of the little-endian quadword wraw at (%rsi); the stepper emits  *)
(* word_bytereverse).                                                        *)
(*                                                                           *)
(* Closer (int64 simplification vs SHA-256).  Because SHA-512 is uniformly   *)
(* 64-bit, X86_STEPS_TAC produces NO int32<->int64 word_zx round-trips (the  *)
(* zerotop_32 operand model that SHA-256's closer had to collapse), so this  *)
(* closer drops both the SHA256_WORD_ZX_* collapse rewrites AND the          *)
(* AP_TERM_TAC (there is no outer word_zx wrapper to strip).  After the four *)
(* big-Sigma/Choose/Maj bridges from sha512_bridge.ml refold the hardware    *)
(* chains to the spec atoms, each register equals a word_add tree over those *)
(* atoms in a different association from the unfolded sha512_round; bare      *)
(* REPEAT CONJ_TAC THEN CONV_TAC WORD_RULE (AC over word_add) closes all     *)
(* conjuncts including the W-ring store.  The four bridge LHS chains were     *)
(* confirmed to match the emitted operand order syntactically (the Phase-3   *)
(* "confirm operand order in Phase 4" task).                                 *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_ROUND0 = prove
 (`!pc K512 kbase stackptr dataptr a b c d e f g h wraw k.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x6b) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read (memory :> bytes64 dataptr) s = wraw /\
            read (memory :> bytes64 kbase) s = (k:int64) /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0xd7) /\
            read R11 s = EL 0 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RAX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RBX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RCX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RDX s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R8 s  = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R9 s  = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R10 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read (memory :> bytes64 stackptr) s = word_bytereverse wraw)
       (MAYCHANGE [RIP;RDI;RBP;RDX;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 stackptr] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--33) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  (* refold the hardware rotate/xor/and chains to the spec primitives *)
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
  (* unfold one spec round and match each working variable up to word_add AC *)
  REWRITE_TAC[sha512_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 4 - the second head round (odd parity), standalone.                 *)
(*                                                                           *)
(* This validates the two cross-round threads that ROUND0 could not exhibit  *)
(* (being the first round, it seeds the carries fresh):                      *)
(*                                                                           *)
(*  - REGISTER ROLE ROTATION (period 8).  With the canonical register file   *)
(*    C = [RAX;RBX;RCX;RDX;R8;R9;R10;R11] = (a,b,c,d,e,f,g,h) at round 0,    *)
(*    working-variable role j at round t lives in C[(j - t) MOD 8].  So at    *)
(*    round 1 the inputs are a->R11, b->RAX, c->RBX, d->RCX, e->RDX, f->R8,   *)
(*    g->R9, h->R10, and the outputs rotate one place further (EL 0 -> R10). *)
(*                                                                           *)
(*  - MAJ CARRIED-XOR (period 2).  The scalar code carries the value b^c     *)
(*    into each round's Maj (since b_{t+1}=a_t, c_{t+1}=b_t, we have         *)
(*    b_{t+1}^c_{t+1} = a_t^b_t, computed at the END of round t).  The carry  *)
(*    register alternates: round 0 leaves a0^b0 in R15, which round 1        *)
(*    consumes; round 1 leaves a1^b1 in RDI, which round 2 consumes.  Hence   *)
(*    round 1's precondition supplies R15 = word_xor b c (its own b^c, = the  *)
(*    previous round's a^b) and its postcondition exposes RDI = word_xor a b. *)
(*                                                                           *)
(* Entry pc+0xd7 (orig 0xdb, round-1 W-load), exit pc+0x142 (orig 0x146,     *)
(* round-2 W-load); 32 instructions.  W read from (dataptr+8), stored to      *)
(* (stackptr+8), round constant k from kbase.  The Phase-4 closer discharges  *)
(* it unchanged, confirming the closer is parity-independent.  Together with  *)
(* ROUND0 this shows every head round is uniform up to the register          *)
(* permutation and the carry-register swap, so the 16-round head section can  *)
(* be composed by cut-points (Phase 5).                                      *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_ROUND1 = prove
 (`!pc K512 kbase stackptr dataptr a b c d e f g h wraw k.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0xd7) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read R15 s = word_xor (b:int64) (c:int64) /\
            read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw /\
            read (memory :> bytes64 kbase) s = (k:int64) /\
            read R11 s = (a:int64) /\
            read RAX s = (b:int64) /\
            read RBX s = (c:int64) /\
            read RCX s = (d:int64) /\
            read RDX s = (e:int64) /\
            read R8 s  = (f:int64) /\
            read R9 s  = (g:int64) /\
            read R10 s = (h:int64))
       (\s. read RIP s = word (pc + 0x142) /\
            read R10 s = EL 0 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R11 s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RAX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RBX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RCX s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RDX s = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R8 s  = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read R9 s  = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k (word_bytereverse wraw)) /\
            read RDI s = word_xor (a:int64) (b:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = word_bytereverse wraw)
       (MAYCHANGE [RIP;RDI;RBP;R10;R11;RAX;RBX;RCX;RDX;R8;R9;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 8))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--32) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
  REWRITE_TAC[sha512_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 5 - composing head rounds by cut-points: the 2-round prototype.     *)
(*                                                                           *)
(* This establishes the composition MECHANISM that scales to all 16 head     *)
(* rounds.  The naive alternative - step both rounds (65 instrs) and close    *)
(* the whole thing with one WORD_RULE - FAILS: round 0's output word_add tree *)
(* feeds round 1's sha512_maj / sha512_choose as NON-ATOMIC arguments, and    *)
(* since those primitives are opaque, WORD_RULE cannot reconcile the two      *)
(* associations of the argument trees.  Cut-points are therefore mandatory.   *)
(*                                                                           *)
(* The mechanism (one cut per round boundary):                               *)
(*   1. ENSURES_SEQUENCE_TAC at the boundary pc (pc+0xd7) with a cut          *)
(*      predicate Q stating the post-round-0 working state in SPEC TERMS -    *)
(*      each register holds EL j (sha512_round ...) in its rotated position,  *)
(*      and the Maj-carry register R15 holds                                  *)
(*      word_xor (EL 1 ..) (EL 2 ..) (= new-a ^ new-b of round 0, the form    *)
(*      round 1's Maj precondition consumes since b_1=a_0, c_1=b_0).          *)
(*   2. Segment 1 (round 0) closes with the standard round closer.            *)
(*   3. In segment 2, ABBREV_TAC the inner round result (rr0) BEFORE          *)
(*      stepping.  This keeps the inner round OPAQUE, so REWRITE_TAC          *)
(*      [sha512_round] in segment 2 unfolds only the OUTER (round 1)          *)
(*      application - the inner EL j rr0 atoms match the precondition         *)
(*      registers directly and the closer's WORD_RULE sees only one round's  *)
(*      word_add tree (no nested-opaque blow-up).                            *)
(*                                                                           *)
(* K-walk across the cut: round 0's "lea 0x8(%rbp),%rbp" (orig 0xd4) leaves   *)
(* RBP = kbase+8 (K[1] location, byte 8 per the doubled-row +32-per-pair      *)
(* formula); round 1 reads k1 there.  This is the int64 analogue of           *)
(* SHA-256 SHA256_BLOCK_NOHW_HEAD2; the segment closers are the parity-       *)
(* independent ROUND0/ROUND1 closer (TRY AP_TERM_TAC is a no-op at int64 -    *)
(* there is no word_zx wrapper - but harmless, kept for template parity).     *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_HEAD2 = prove
 (`!pc K512 kbase stackptr dataptr a b c d e f g h wraw0 wraw1 k0 k1.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,16) /\
     nonoverlapping (stackptr:int64,128) (dataptr:int64,16)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x6b) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read (memory :> bytes64 dataptr) s = wraw0 /\
            read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw1 /\
            read (memory :> bytes64 kbase) s = (k0:int64) /\
            read (memory :> bytes64 (word_add kbase (word 8))) s = (k1:int64) /\
            read RAX s = (a:int64) /\ read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\ read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\ read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\ read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0x142) /\
            read R10 s = EL 0 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read R11 s = EL 1 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read RAX s = EL 2 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read RBX s = EL 3 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read RCX s = EL 4 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read RDX s = EL 5 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read R8 s  = EL 6 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read R9 s  = EL 7 (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) /\
            read (memory :> bytes64 stackptr) s = word_bytereverse wraw0 /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = word_bytereverse wraw1)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 stackptr] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 8))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 0xd7`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 8) /\
        read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw1 /\
        read (memory :> bytes64 (word_add kbase (word 8))) s = k1 /\
        read R11 s = EL 0 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RAX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RBX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RCX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RDX s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R8 s  = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R9 s  = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R10 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R15 s = word_xor (EL 1 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) (EL 2 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read (memory :> bytes64 stackptr) s = word_bytereverse wraw0` THEN
  CONJ_TAC THENL
   [(* segment 1: round 0, pc+0x6b .. pc+0xd7 *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--33) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
                SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    (* segment 2: round 1, pc+0xd7 .. pc+0x142, inner round kept opaque as rr0 *)
    ABBREV_TAC `rr0:int64 list = sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)` THEN
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--32) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
                SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE]);;

(* ------------------------------------------------------------------------- *)
(* Phase 5 - composing head rounds by cut-points: the 4-round lemma.         *)
(*                                                                           *)
(* Exactly HEAD2 with two MORE cut-points (pc+0x142 after round 1, pc+0x1ad  *)
(* after round 2); the final segment is round 3, exit pc+0x218.  Framing A    *)
(* (explicit nested sha512_round, one free k_i / wraw_i per round).  This is  *)
(* the first lemma past HEAD2 to cross BOTH the +24 odd K-stride and the      *)
(* full period-2 Maj-carry swap cycle (R15 after r0 -> RDI after r1 -> R15    *)
(* after r2 -> RDI after r3), confirming the cut mechanism is K-walk and      *)
(* parity agnostic at int64.                                                 *)
(*                                                                           *)
(* KEY SHA-512 layout delta vs SHA-256 (doubled-row K512): the round          *)
(* constants are NOT contiguous - per orchestrator/logs/sha512-phase0-facts   *)
(* §2, K[t] is at byte 32*(t DIV 2) + 8*(t MOD 2), so k0@kbase+0, k1@+8,      *)
(* k2@+32, k3@+40 (NOT +16/+24).  The RBP cursor advances +8 (even t,         *)
(* "lea 0x8(%rbp)") then +24 (odd t, "lea 0x18(%rbp)"), net +32 per pair, so  *)
(* RBP = kbase, kbase+8, kbase+32, kbase+40 at the start of rounds 0..3.       *)
(* The W words and stack-ring slots ARE contiguous 8-byte (w_i@dataptr+8i,    *)
(* stored to stackptr+8i), unlike the K table.                               *)
(*                                                                           *)
(* Register rotation (role j after t rounds in C[(j-t) MOD 8], canonical      *)
(* C = [RAX;RBX;RCX;RDX;R8;R9;R10;R11]) and the period-2 Maj carry, verified  *)
(* against the binary (session 005):                                         *)
(*   after r0: a..h in R11,RAX,RBX,RCX,RDX,R8,R9,R10  ; carry-out R15        *)
(*   after r1: a..h in R10,R11,RAX,RBX,RCX,RDX,R8,R9  ; carry-out RDI        *)
(*   after r2: a..h in R9,R10,R11,RAX,RBX,RCX,RDX,R8  ; carry-out R15        *)
(*   after r3: a..h in R8,R9,R10,R11,RAX,RBX,RCX,RDX  ; carry-out RDI        *)
(* Each segment uses the standard round closer; later segments ABBREV_TAC    *)
(* the running inner state (rr0/rr1/rr2) BEFORE stepping, so REWRITE_TAC      *)
(* [sha512_round] unfolds only that segment's outer round (no nested-opaque  *)
(* blow-up), per the HEAD2 mechanism.                                        *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_HEAD4 = prove
 (`!pc K512 kbase stackptr dataptr a b c d e f g h
     wraw0 wraw1 wraw2 wraw3 k0 k1 k2 k3.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,48) /\
     nonoverlapping (stackptr:int64,128) (dataptr:int64,32)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x6b) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read (memory :> bytes64 dataptr) s = wraw0 /\
            read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw1 /\
            read (memory :> bytes64 (word_add dataptr (word 16))) s = wraw2 /\
            read (memory :> bytes64 (word_add dataptr (word 24))) s = wraw3 /\
            read (memory :> bytes64 kbase) s = (k0:int64) /\
            read (memory :> bytes64 (word_add kbase (word 8))) s = (k1:int64) /\
            read (memory :> bytes64 (word_add kbase (word 32))) s = (k2:int64) /\
            read (memory :> bytes64 (word_add kbase (word 40))) s = (k3:int64) /\
            read RAX s = (a:int64) /\ read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\ read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\ read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\ read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0x218) /\
            read R8 s  = EL 0 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read R9 s  = EL 1 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read R10 s = EL 2 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read R11 s = EL 3 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read RAX s = EL 4 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read RBX s = EL 5 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read RCX s = EL 6 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read RDX s = EL 7 (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) /\
            read (memory :> bytes64 stackptr) s = word_bytereverse wraw0 /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = word_bytereverse wraw1 /\
            read (memory :> bytes64 (word_add stackptr (word 16))) s = word_bytereverse wraw2 /\
            read (memory :> bytes64 (word_add stackptr (word 24))) s = word_bytereverse wraw3)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 stackptr] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 8))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 16))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 24))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  (* ---- cut after round 0 : pc+0xd7 ---- *)
  ENSURES_SEQUENCE_TAC `pc + 0xd7`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 8) /\
        read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw1 /\
        read (memory :> bytes64 (word_add dataptr (word 16))) s = wraw2 /\
        read (memory :> bytes64 (word_add dataptr (word 24))) s = wraw3 /\
        read (memory :> bytes64 (word_add kbase (word 8))) s = k1 /\
        read (memory :> bytes64 (word_add kbase (word 32))) s = k2 /\
        read (memory :> bytes64 (word_add kbase (word 40))) s = k3 /\
        read R11 s = EL 0 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RAX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RBX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RCX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read RDX s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R8 s  = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R9 s  = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R10 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) /\
        read R15 s = word_xor (EL 1 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) (EL 2 (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0))) /\
        read (memory :> bytes64 stackptr) s = word_bytereverse wraw0` THEN
  CONJ_TAC THENL
   [(* segment 1: round 0, pc+0x6b .. pc+0xd7 *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--33) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
                SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  (* ---- cut after round 1 : pc+0x142 ---- *)
  ABBREV_TAC `rr0:int64 list = sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)` THEN
  ENSURES_SEQUENCE_TAC `pc + 0x142`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 32) /\
        read (memory :> bytes64 (word_add dataptr (word 16))) s = wraw2 /\
        read (memory :> bytes64 (word_add dataptr (word 24))) s = wraw3 /\
        read (memory :> bytes64 (word_add kbase (word 32))) s = k2 /\
        read (memory :> bytes64 (word_add kbase (word 40))) s = k3 /\
        read R10 s = EL 0 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read R11 s = EL 1 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read RAX s = EL 2 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read RBX s = EL 3 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read RCX s = EL 4 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read RDX s = EL 5 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read R8 s  = EL 6 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read R9 s  = EL 7 (sha512_round rr0 k1 (word_bytereverse wraw1)) /\
        read RDI s = word_xor (EL 1 (sha512_round rr0 k1 (word_bytereverse wraw1))) (EL 2 (sha512_round rr0 k1 (word_bytereverse wraw1))) /\
        read (memory :> bytes64 stackptr) s = word_bytereverse wraw0 /\
        read (memory :> bytes64 (word_add stackptr (word 8))) s = word_bytereverse wraw1` THEN
  CONJ_TAC THENL
   [(* segment 2: round 1, pc+0xd7 .. pc+0x142, inner round rr0 opaque *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--32) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
                SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  (* ---- cut after round 2 : pc+0x1ad ---- *)
  ABBREV_TAC `rr1:int64 list = sha512_round rr0 k1 (word_bytereverse wraw1)` THEN
  ENSURES_SEQUENCE_TAC `pc + 0x1ad`
   `\s. read RSI s = dataptr /\ read RSP s = stackptr /\
        read RBP s = word_add kbase (word 40) /\
        read (memory :> bytes64 (word_add dataptr (word 24))) s = wraw3 /\
        read (memory :> bytes64 (word_add kbase (word 40))) s = k3 /\
        read R9 s  = EL 0 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read R10 s = EL 1 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read R11 s = EL 2 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read RAX s = EL 3 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read RBX s = EL 4 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read RCX s = EL 5 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read RDX s = EL 6 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read R8 s  = EL 7 (sha512_round rr1 k2 (word_bytereverse wraw2)) /\
        read R15 s = word_xor (EL 1 (sha512_round rr1 k2 (word_bytereverse wraw2))) (EL 2 (sha512_round rr1 k2 (word_bytereverse wraw2))) /\
        read (memory :> bytes64 stackptr) s = word_bytereverse wraw0 /\
        read (memory :> bytes64 (word_add stackptr (word 8))) s = word_bytereverse wraw1 /\
        read (memory :> bytes64 (word_add stackptr (word 16))) s = word_bytereverse wraw2` THEN
  CONJ_TAC THENL
   [(* segment 3: round 2, pc+0x142 .. pc+0x1ad, inner round rr1 opaque *)
    ENSURES_INIT_TAC "s0" THEN
    X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--32) THEN
    ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
    REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
                SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
    REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
    CONV_TAC(DEPTH_CONV EL_CONV) THEN
    REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE;
    ALL_TAC] THEN
  (* ---- segment 4: round 3, pc+0x1ad .. pc+0x218, inner round rr2 opaque ---- *)
  ABBREV_TAC `rr2:int64 list = sha512_round rr1 k2 (word_bytereverse wraw2)` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--32) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE] THEN
  REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ------------------------------------------------------------------------- *)
(* Phase 5 - composing head rounds by cut-points: the 8-round lemma.         *)
(*                                                                           *)
(* HEAD4 scaled to 8 rounds (7 inline ENSURES_SEQUENCE_TAC cuts at the head  *)
(* round boundaries pc+0xd7/0x142/0x1ad/0x218/0x283/0x2ee/0x359; the final   *)
(* segment is round 7, exit pc+0x3c4).  Mechanically generated from the      *)
(* HEAD2/HEAD4 template by orchestrator/logs/session-006-gen.py, whose N=4   *)
(* output is structurally identical (up to conjunct order + comments) to the *)
(* hand-written HEAD4 above (regression-checked).                            *)
(*                                                                           *)
(* Past HEAD4, this first crosses the round-4..7 K-stride continuation        *)
(* (doubled-row, k4..k7 at kbase+64/+72/+96/+104 = 32*(t DIV 2)+8*(t MOD 2)) *)
(* and two more full Maj-carry swap cycles.  After 8 rounds the period-8      *)
(* register rotation realigns to canonical (a->RAX,..,h->R11), so the         *)
(* postcondition is a clean compress-8 state with EL j in C[j].  kbase span   *)
(* 112 = koff(7)+8 = 104+8, wide enough to carry every K read past the        *)
(* W-ring stores.  Each segment uses the parity-independent int64 round       *)
(* closer; later segments ABBREV_TAC the running inner state (rr0..rr6)       *)
(* BEFORE stepping so REWRITE_TAC[sha512_round] unfolds only that segment's   *)
(* outer round (no nested-opaque blow-up), per the HEAD2 mechanism.          *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_HEAD8 = prove
