     nonoverlapping (stackptr:int64,128) (kbase:int64,112) /\
     nonoverlapping (stackptr:int64,128) (dataptr:int64,64)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x6b) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read (memory :> bytes64 dataptr) s = wraw0 /\
            read (memory :> bytes64 (word_add dataptr (word 8))) s = wraw1 /\
            read (memory :> bytes64 (word_add dataptr (word 16))) s = wraw2 /\
            read (memory :> bytes64 (word_add dataptr (word 24))) s = wraw3 /\
            read (memory :> bytes64 (word_add dataptr (word 32))) s = wraw4 /\
            read (memory :> bytes64 (word_add dataptr (word 40))) s = wraw5 /\
            read (memory :> bytes64 (word_add dataptr (word 48))) s = wraw6 /\
            read (memory :> bytes64 (word_add dataptr (word 56))) s = wraw7 /\
            read (memory :> bytes64 kbase) s = (k0:int64) /\
            read (memory :> bytes64 (word_add kbase (word 8))) s = (k1:int64) /\
            read (memory :> bytes64 (word_add kbase (word 32))) s = (k2:int64) /\
            read (memory :> bytes64 (word_add kbase (word 40))) s = (k3:int64) /\
            read (memory :> bytes64 (word_add kbase (word 64))) s = (k4:int64) /\
            read (memory :> bytes64 (word_add kbase (word 72))) s = (k5:int64) /\
            read (memory :> bytes64 (word_add kbase (word 96))) s = (k6:int64) /\
            read (memory :> bytes64 (word_add kbase (word 104))) s = (k7:int64) /\
            read RAX s = (a:int64) /\ read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\ read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\ read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\ read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0x3c4) /\
            read RAX  s = EL 0 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read RBX  s = EL 1 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read RCX  s = EL 2 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read RDX  s = EL 3 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read R8   s = EL 4 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read R9   s = EL 5 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read R10  s = EL 6 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
            read R11  s = EL 7 (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round [a;b;c;d;e;f;g;h] k0 (word_bytereverse wraw0)) k1 (word_bytereverse wraw1)) k2 (word_bytereverse wraw2)) k3 (word_bytereverse wraw3)) k4 (word_bytereverse wraw4)) k5 (word_bytereverse wraw5)) k6 (word_bytereverse wraw6)) k7 (word_bytereverse wraw7)) /\
