(* ========================================================================= *)
(* Phase 6 - abstract-m restatement infrastructure + HEAD16_ABS.             *)
(*                                                                           *)
(* The inner-loop chain (Phase 8/9) is built over the OPAQUE working state   *)
(* sha512_compress_rounds m hsh N rather than the explicit nested            *)
(* sha512_round term, so each per-iteration seam is O(1) in N and the x4     *)
(* chain does not explode (the pure-unroll route was measured non-viable in  *)
(* the SHA-256 run, session-021).  COMPRESS_ROUNDS_CONV unfolds              *)
(* compress_rounds N into the N-deep nest with symbolic EL t sha512_constants*)
(* / sha512_msg_schedule m t; SCHED_LT16_CONV reduces head schedule words    *)
(* (t<16) to EL t m.  int64 clone of the SHA-256 sha256_compress.ml block.   *)
(* ========================================================================= *)

let COMPRESS_ROUNDS_SUC = prove
 (`sha512_compress_rounds m hsh (SUC n) =
     sha512_round (sha512_compress_rounds m hsh n)
                  (EL n sha512_constants)
                  (sha512_msg_schedule m n)`,
  REWRITE_TAC[ADD1; sha512_compress_rounds]);;

let COMPRESS_ROUNDS_CONV : conv =
  let cr0 = CONJUNCT1 sha512_compress_rounds in
  let rec conv tm =
    let n = dest_small_numeral (rand tm) in
    if n = 0 then REWR_CONV cr0 tm
    else
      (RAND_CONV num_CONV THENC
       REWR_CONV COMPRESS_ROUNDS_SUC THENC
       RATOR_CONV(RATOR_CONV(RAND_CONV conv))) tm in
  conv;;

(* sha512_msg_schedule m t  ->  EL t m   for literal t < 16 *)
let SCHED_LT16_CONV : conv =
  ONCE_REWRITE_CONV[sha512_msg_schedule] THENC
  RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
  REWRITE_CONV[COND_CLAUSES];;

(* The fold theorem we GSYM to collapse the 16-deep nest into compress_rounds. *)
let HEAD16_FOLD = GEN_ALL (prove
 (`sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16 =
   sha512_round (sha512_round (sha512_round (sha512_round (sha512_round
   (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round
   (sha512_round (sha512_round (sha512_round (sha512_round (sha512_round
   (sha512_round [a;b;c;d;e;f;g;h]
     (EL 0 sha512_constants) (EL 0 m))
     (EL 1 sha512_constants) (EL 1 m))
     (EL 2 sha512_constants) (EL 2 m))
     (EL 3 sha512_constants) (EL 3 m))
     (EL 4 sha512_constants) (EL 4 m))
     (EL 5 sha512_constants) (EL 5 m))
     (EL 6 sha512_constants) (EL 6 m))
     (EL 7 sha512_constants) (EL 7 m))
     (EL 8 sha512_constants) (EL 8 m))
     (EL 9 sha512_constants) (EL 9 m))
     (EL 10 sha512_constants) (EL 10 m))
     (EL 11 sha512_constants) (EL 11 m))
     (EL 12 sha512_constants) (EL 12 m))
     (EL 13 sha512_constants) (EL 13 m))
     (EL 14 sha512_constants) (EL 14 m))
     (EL 15 sha512_constants) (EL 15 m)`,
  CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_CONV THENC ONCE_DEPTH_CONV SCHED_LT16_CONV)) THEN
  REFL_TAC));;

(* Partial unfold to a floor (Phase-7 body lemmas keep compress_rounds (16+16i)). *)
let COMPRESS_ROUNDS_DOWNTO (floor:int) : conv =
  let rec conv tm =
    let n = dest_small_numeral (rand tm) in
    if n <= floor then REFL tm
    else (RAND_CONV num_CONV THENC REWR_CONV COMPRESS_ROUNDS_SUC THENC
          RATOR_CONV(RATOR_CONV(RAND_CONV conv))) tm in
  conv;;

(* List reconstruction for an 8-element state (collapse [EL 0 l;..;EL 7 l] = l). *)
let EL8_RECONSTRUCT = prove
 (`!l:int64 list. LENGTH l = 8
       ==> [EL 0 l; EL 1 l; EL 2 l; EL 3 l; EL 4 l; EL 5 l; EL 6 l; EL 7 l] = l`,
  REPEAT STRIP_TAC THEN POP_ASSUM MP_TAC THEN
  CONV_TAC(LAND_CONV(RAND_CONV(TOP_DEPTH_CONV num_CONV))) THEN
  REWRITE_TAC[LENGTH_EQ_CONS; LENGTH_EQ_NIL] THEN
  STRIP_TAC THEN ASM_REWRITE_TAC[] THEN
  CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;


(* ------------------------------------------------------------------------- *)
(* HEAD16_ABS: HEAD16 restated with post working state                       *)
(*   sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16,                          *)
(* round constants folded to EL t sha512_constants and head message words   *)
(* to EL t m.  DERIVED from HEAD16 by instantiating                          *)
(*   wraw_t := word_bytereverse (EL t m),  k_t := EL t sha512_constants,     *)
(* collapsing the word_bytereverse involution, then folding the nest via     *)
(* GSYM HEAD16_FOLD.  The rodata-base binder is kdat:num (NOT K512) to dodge *)
(* the K512 rodata-constant clash in the SPECL (memory sha512-abstract-m-fold*)
(* gotcha 1).  The extra seam conjuncts (RBP=kbase+256, RDI round-15 carry,  *)
(* scratch R12/R13/R15) are preserved VERBATIM - the abstraction is over the *)
(* working-register EL-values only (Phase-7 needs those conjuncts intact).   *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_HEAD16_ABS = prove
 (`!pc kdat kbase stackptr dataptr a b c d e f g h (m:int64 list).
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,240) /\
     nonoverlapping (stackptr:int64,128) (dataptr:int64,128)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kdat) /\
            read RIP s = word (pc + 0x6b) /\
            read RBP s = kbase /\ read RSP s = stackptr /\ read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read (memory :> bytes64 dataptr) s = word_bytereverse (EL 0 m) /\
            read (memory :> bytes64 (word_add dataptr (word 8))) s = word_bytereverse (EL 1 m) /\
            read (memory :> bytes64 (word_add dataptr (word 16))) s = word_bytereverse (EL 2 m) /\
            read (memory :> bytes64 (word_add dataptr (word 24))) s = word_bytereverse (EL 3 m) /\
            read (memory :> bytes64 (word_add dataptr (word 32))) s = word_bytereverse (EL 4 m) /\
            read (memory :> bytes64 (word_add dataptr (word 40))) s = word_bytereverse (EL 5 m) /\
            read (memory :> bytes64 (word_add dataptr (word 48))) s = word_bytereverse (EL 6 m) /\
            read (memory :> bytes64 (word_add dataptr (word 56))) s = word_bytereverse (EL 7 m) /\
            read (memory :> bytes64 (word_add dataptr (word 64))) s = word_bytereverse (EL 8 m) /\
            read (memory :> bytes64 (word_add dataptr (word 72))) s = word_bytereverse (EL 9 m) /\
            read (memory :> bytes64 (word_add dataptr (word 80))) s = word_bytereverse (EL 10 m) /\
            read (memory :> bytes64 (word_add dataptr (word 88))) s = word_bytereverse (EL 11 m) /\
            read (memory :> bytes64 (word_add dataptr (word 96))) s = word_bytereverse (EL 12 m) /\
            read (memory :> bytes64 (word_add dataptr (word 104))) s = word_bytereverse (EL 13 m) /\
            read (memory :> bytes64 (word_add dataptr (word 112))) s = word_bytereverse (EL 14 m) /\
            read (memory :> bytes64 (word_add dataptr (word 120))) s = word_bytereverse (EL 15 m) /\
            read (memory :> bytes64 kbase) s = EL 0 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 8))) s = EL 1 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 32))) s = EL 2 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 40))) s = EL 3 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 64))) s = EL 4 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 72))) s = EL 5 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 96))) s = EL 6 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 104))) s = EL 7 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 128))) s = EL 8 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 136))) s = EL 9 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 160))) s = EL 10 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 168))) s = EL 11 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 192))) s = EL 12 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 200))) s = EL 13 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 224))) s = EL 14 sha512_constants /\
            read (memory :> bytes64 (word_add kbase (word 232))) s = EL 15 sha512_constants /\
            read RAX s = (a:int64) /\ read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\ read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\ read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\ read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0x72f) /\
            read RBP s = word_add kbase (word 256) /\
            read RAX  s = EL 0 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read RBX  s = EL 1 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read RCX  s = EL 2 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read RDX  s = EL 3 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read R8   s = EL 4 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read R9   s = EL 5 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read R10  s = EL 6 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read R11  s = EL 7 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16) /\
            read R12 s = EL 1 m /\
            read R13 s = word_ror (EL 1 m) 7 /\
            read R15 s = EL 14 m /\
            read RDI s = word_xor (EL 1 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16)) (EL 2 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 16)) /\
            read (memory :> bytes64 stackptr) s = EL 0 m /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = EL 1 m /\
            read (memory :> bytes64 (word_add stackptr (word 16))) s = EL 2 m /\
            read (memory :> bytes64 (word_add stackptr (word 24))) s = EL 3 m /\
            read (memory :> bytes64 (word_add stackptr (word 32))) s = EL 4 m /\
            read (memory :> bytes64 (word_add stackptr (word 40))) s = EL 5 m /\
            read (memory :> bytes64 (word_add stackptr (word 48))) s = EL 6 m /\
            read (memory :> bytes64 (word_add stackptr (word 56))) s = EL 7 m /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = EL 8 m /\
            read (memory :> bytes64 (word_add stackptr (word 72))) s = EL 9 m /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = EL 10 m /\
            read (memory :> bytes64 (word_add stackptr (word 88))) s = EL 11 m /\
            read (memory :> bytes64 (word_add stackptr (word 96))) s = EL 12 m /\
            read (memory :> bytes64 (word_add stackptr (word 104))) s = EL 13 m /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = EL 14 m /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s = EL 15 m)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 stackptr] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 8))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 16))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 24))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 32))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 40))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 48))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 56))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 64))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 72))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 80))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 88))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 96))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 104))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 112))] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 120))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REPEAT GEN_TAC THEN STRIP_TAC THEN
  MP_TAC(SPECL
   [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`; `dataptr:int64`;
    `a:int64`; `b:int64`; `c:int64`; `d:int64`;
    `e:int64`; `f:int64`; `g:int64`; `h:int64`;
    `word_bytereverse (EL 0 m):int64`; `word_bytereverse (EL 1 m):int64`; `word_bytereverse (EL 2 m):int64`; `word_bytereverse (EL 3 m):int64`;
    `word_bytereverse (EL 4 m):int64`; `word_bytereverse (EL 5 m):int64`; `word_bytereverse (EL 6 m):int64`; `word_bytereverse (EL 7 m):int64`;
    `word_bytereverse (EL 8 m):int64`; `word_bytereverse (EL 9 m):int64`; `word_bytereverse (EL 10 m):int64`; `word_bytereverse (EL 11 m):int64`;
    `word_bytereverse (EL 12 m):int64`; `word_bytereverse (EL 13 m):int64`; `word_bytereverse (EL 14 m):int64`; `word_bytereverse (EL 15 m):int64`;
    `EL 0 sha512_constants:int64`; `EL 1 sha512_constants:int64`; `EL 2 sha512_constants:int64`; `EL 3 sha512_constants:int64`;
    `EL 4 sha512_constants:int64`; `EL 5 sha512_constants:int64`; `EL 6 sha512_constants:int64`; `EL 7 sha512_constants:int64`;
    `EL 8 sha512_constants:int64`; `EL 9 sha512_constants:int64`; `EL 10 sha512_constants:int64`; `EL 11 sha512_constants:int64`;
    `EL 12 sha512_constants:int64`; `EL 13 sha512_constants:int64`; `EL 14 sha512_constants:int64`; `EL 15 sha512_constants:int64`]
   SHA512_BLOCK_NOHW_HEAD16) THEN
  ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[WORD_BYTEREVERSE_BYTEREVERSE; GSYM HEAD16_FOLD]);;

(* ------------------------------------------------------------------------- *)
(* BODY1 - ONE fused rounds_16_xx sub-round (absolute round 16).             *)
(*                                                                           *)
(* Entry pc+0x72f (= HEAD16 exit; orig 0x733), exit pc+0x7d1 (orig 0x7d5 =    *)
(* sub-round-0's deferred Sigma0 fold pc+0x7d2 + 3), 47 instructions.        *)
(* Decoded from objdump of x86/sha512/sha512_compress.o (session 008):       *)
(*   W[16] = sigma0(v1) + v9 + v0 + sigma1(v14)   [stored back to slot 0]    *)
(*   sigma0 chain ror7/xor/ror1/shr7   = SHA512_MSG_SIGMA0_BRIDGE LHS         *)
(*   sigma1 chain ror42/xor/ror19/shr6 = SHA512_MSG_SIGMA1_BRIDGE LHS         *)
(* then one compression round on W[16] and K[16] from (%rbp).  Register      *)
(* file / Maj-carry / K-walk continue from the head unchanged (round 16 is   *)
(* canonical, 16 mod 8 = 0; a->RAX..h->R11).  Round 16 is EVEN: sigma1        *)
(* scratch in R15, Maj carry-in in RDI (parity matches the head).            *)
(*                                                                           *)
(* Framing A (single-sub-round analogue of ROUND0/ROUND1, mirrors SHA-256    *)
(* BODY1): free round constant k16, opaque ring words v0..v15 (each = the    *)
(* head's word_bytereverse wraw_j).  Exit asserts the 8 working vars         *)
(* (sha512_round of [a..h] with the freshly expanded message word) + the     *)
(* rewritten ring slot 0.  Live exit sigma/Maj scratch for round 17 is left  *)
(* in MAYCHANGE (the composition lemma carries it forward across seams).     *)
(* int64 throughout: NO word_zx (SHA-512 is uniformly 64-bit).               *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_BODY1 = prove
 (`!pc K512 kbase stackptr a b c d e f g h
     v0 v1 v2 v3 v4 v5 v6 v7 v8 v9 v10 v11 v12 v13 v14 v15 k16.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kbase:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x72f) /\
            read RBP s = kbase /\
            read RSP s = stackptr /\
            read R12 s = (v1:int64) /\
            read R13 s = word_ror (v1:int64) 7 /\
            read R15 s = (v14:int64) /\
            read RDI s = word_xor (b:int64) (c:int64) /\
            read (memory :> bytes64 kbase) s = (k16:int64) /\
            read (memory :> bytes64 stackptr) s = v0 /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = v1 /\
            read (memory :> bytes64 (word_add stackptr (word 16))) s = v2 /\
            read (memory :> bytes64 (word_add stackptr (word 24))) s = v3 /\
            read (memory :> bytes64 (word_add stackptr (word 32))) s = v4 /\
            read (memory :> bytes64 (word_add stackptr (word 40))) s = v5 /\
            read (memory :> bytes64 (word_add stackptr (word 48))) s = v6 /\
            read (memory :> bytes64 (word_add stackptr (word 56))) s = v7 /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = v8 /\
            read (memory :> bytes64 (word_add stackptr (word 72))) s = v9 /\
            read (memory :> bytes64 (word_add stackptr (word 80))) s = v10 /\
            read (memory :> bytes64 (word_add stackptr (word 88))) s = v11 /\
            read (memory :> bytes64 (word_add stackptr (word 96))) s = v12 /\
            read (memory :> bytes64 (word_add stackptr (word 104))) s = v13 /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = v14 /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s = v15 /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64))
       (\s. read RIP s = word (pc + 0x7d1) /\
            read R11 s = EL 0 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read RAX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read RBX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read RCX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read RDX s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read R8 s  = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read R9 s  = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read R10 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k16
              (word_add (word_add (sha512_msg_sigma_1 v14) v9)
                        (word_add (sha512_msg_sigma_0 v1) v0))) /\
            read (memory :> bytes64 stackptr) s =
              word_add (word_add (sha512_msg_sigma_1 v14) v9)
                       (word_add (sha512_msg_sigma_0 v1) v0))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 stackptr] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--47) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE;
              SHA512_MSG_SIGMA0_BRIDGE; SHA512_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha512_round] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

