(* BODY15_ABS: BODY15 (rounds 16..30) restated over the OPAQUE working state  *)
(* sha512_compress_rounds m sin (16 -> 31).  Built programmatically by         *)
(* instantiating BODY15 with                                                  *)
(*   a..h    := EL j (sha512_compress_rounds m sin 16),                       *)
(*   vj      := EL j m,                                                        *)
(*   k(16+t) := EL (16+t) sha512_constants,                                   *)
(* then folding the post nest to sha512_compress_rounds m sin 31 (via GSYM of *)
(* a partial unfold from 31 down to 16, with the message-schedule words memoed *)
(* over the abstract block m) and collapsing the base [EL 0 sin16;..] = sin16  *)
(* (EL8_RECONSTRUCT, needing LENGTH sin = 8).  The seam is O(1) in the round   *)
(* count, so the inner-loop iteration composes x4 with no term explosion.      *)
(* All helpers are locally scoped; only SHA512_BLOCK_NOHW_BODY15_ABS escapes.  *)
(* The 16 ring slots / round-31 scratch stay as explicit schedule expansions   *)
(* over EL j m (the Phase-8 seam consumes them); only the working-state nest   *)
(* is abstracted.  Uses kdat:num (NOT `K512`) for the rodata-base slot to dodge *)
(* the byte-list-constant type clash in SPECL (memory sha512-abstract-m-fold   *)
(* gotcha 1).                                                                 *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_BODY15_ABS =
  (* schedule memo over abstract m (EL t m at the base, no length hyp). *)
  let tt_tm = `t:num` in
  let msched_pat = `sha512_msg_schedule m t` in
  let instM t = vsubst [mk_small_numeral t,tt_tm] msched_pat in
  let schedM = Array.make 64 TRUTH in
  (for t = 0 to 15 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
                           REWRITE_CONV[COND_CLAUSES] THENC
                           TRY_CONV(LAND_CONV NUM_RED_CONV)))
         (REWR_CONV sha512_msg_schedule (instM t))
   done;
   for t = 16 to 31 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
           REWRITE_CONV[schedM.(t-2); schedM.(t-7); schedM.(t-15); schedM.(t-16)]))
         (REWR_CONV sha512_msg_schedule (instM t))
   done);
  (* post-state fold: compress_rounds m sin 31 = sha512_round^15            *)
  (*   (compress_rounds m sin 16) (EL 16 c)(sched 16) .. (EL 30 c)(sched 30) *)
  let body15_fold_m = prove
   (mk_eq(`sha512_compress_rounds m sin 31`,
          rhs(concl(
            (COMPRESS_ROUNDS_DOWNTO 16 THENC
             REWRITE_CONV(map (fun t -> schedM.(t)) (16--30)))
            `sha512_compress_rounds m sin 31`))),
    CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_DOWNTO 16 THENC
                       REWRITE_CONV(map (fun t -> schedM.(t)) (16--30)))) THEN
    REFL_TAC) in
