  let sin16_len = prove
   (`LENGTH (sin:int64 list) = 8
       ==> [EL 0 (sha512_compress_rounds m sin 16);
            EL 1 (sha512_compress_rounds m sin 16);
            EL 2 (sha512_compress_rounds m sin 16);
            EL 3 (sha512_compress_rounds m sin 16);
            EL 4 (sha512_compress_rounds m sin 16);
            EL 5 (sha512_compress_rounds m sin 16);
            EL 6 (sha512_compress_rounds m sin 16);
            EL 7 (sha512_compress_rounds m sin 16)]
           = sha512_compress_rounds m sin 16`,
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA512_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  (* instantiate BODY15 (43 binders: pc K512 kbase stackptr a..h v0..v15 k16..k30). *)
  (* NB: use kdat:num for the rodata-base slot, NOT `K512` — the latter parses
     as the byte-list constant from define_assert_relocs_from_elf and type-clashes
     against BODY15's :num binder (memory sha512-abstract-m-fold gotcha 1). *)
  let inst_args =
    [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`] @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`]
                    `EL j (sha512_compress_rounds m sin 16):int64`) (0--7)) @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`] `EL j (m:int64 list):int64`) (0--15)) @
    (map (fun t -> vsubst [mk_small_numeral t,`t:num`]
                    `EL t sha512_constants:int64`) (16--30)) in
  let body15_inst = SPECL inst_args SHA512_BLOCK_NOHW_BODY15 in
  let th0 = DISCH `LENGTH (sin:int64 list) = 8` body15_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sin16_len; GSYM body15_fold_m]
    (UNDISCH th0)));;


(* ========================================================================= *)
(* Phase 8 - ROUND31: the 16th (last) rounds_16_xx sub-round, the one BODY15  *)
(* deliberately omits because its deferred Sigma0 fold sits PAST the back-edge*)
(* jne.  Per-iteration tail after BODY15: pc+0x10c6 (BODY15 exit) -> pc+0x1156*)
(* (just before the sentinel cmpb $0,0x7(%rbp)), 42 instructions.  Round 31 is*)
(* ODD (sigma1 scratch in RDI, Maj carry-in in R15); roles a=RBX..h=RAX.  It  *)
(* reads ring slot 8 (=w24) at stackptr+64 and slot 15 (=w15) at stackptr+120,*)
(* sigma0 src w16 from R12/R13, sigma1 src w29 from RDI, K31 from (%rbp)=kb.   *)
(* W31 = sigma1(w29)+w24+sigma0(w16)+w15 stored back to ring slot 15.  Exit is *)
(* a SPLIT state: RAX = EL 0 (round) - Sigma0(a), R14 = Sigma0(a) (deferred    *)
(* fold), RBX..R11 = EL 1..7 directly.  Closer identical to BODY1/BODY15.      *)
(* ========================================================================= *)
(* Phase 8 - SHA512 ROUND31 development driver.
   Run AFTER `loadt "x86/proofs/sha512_compress.ml"` on a warm server.
   The 16th (last) rounds_16_xx sub-round (round 31), int64 clone of
   SHA256_BLOCK_NOHW_ROUND31.  Entry pc+0x10c6 (= BODY15 exit), exit pc+0x1156
   (just before the sentinel cmpb $0,7(%rbp)), 42 instructions.

   Round 31 is ODD (sigma1 scratch in RDI, Maj carry-in in R15), roles:
     a=RBX b=RCX c=RDX d=R8 e=R9 f=R10 g=R11 h=RAX.
   Reads ring slot 8 (=w24) at stackptr+64, slot 15 (=w15) at stackptr+120,
   sigma0 src w16 (slot0) from R12/R13, sigma1 src w29 (slot13) from RDI,
   K31 from (%rbp)=kb.  W31 = sigma1(w29)+w24+sigma0(w16)+w15 stored to slot15.
   SPLIT exit: RAX = EL0(round) - Sigma0(a), R14 = Sigma0(a). *)

let SHA512_BLOCK_NOHW_ROUND31 = prove
 (`!pc K512 kb stackptr a b c d e f g h w16 w24 w29 w15 k31.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kb:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x10c6) /\
            read RBP s = kb /\ read RSP s = stackptr /\
            read R12 s = (w16:int64) /\
            read R13 s = word_ror (w16:int64) 7 /\
            read RDI s = (w29:int64) /\
            read R15 s = word_xor (b:int64) (c:int64) /\
            read (memory :> bytes64 kb) s = (k31:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = w24 /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s = w15 /\
            read RBX s = (a:int64) /\ read RCX s = (b:int64) /\
            read RDX s = (c:int64) /\ read R8  s = (d:int64) /\
            read R9  s = (e:int64) /\ read R10 s = (f:int64) /\
            read R11 s = (g:int64) /\ read RAX s = (h:int64))
       (\s. read RIP s = word (pc + 0x1156) /\
            read RBP s = word_add kb (word 24) /\
            read RSP s = stackptr /\
            read RBX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read RCX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read RDX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R8  s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R9  s = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R10 s = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R11 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read RAX s = word_sub (EL 0 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15)))) (sha512_hash_sigma_0 a) /\
            read R14 s = sha512_hash_sigma_0 a /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s =
              word_add (word_add (sha512_msg_sigma_1 w29) w24)
                       (word_add (sha512_msg_sigma_0 w16) w15))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 120))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--42) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE;
              SHA512_MSG_SIGMA0_BRIDGE; SHA512_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;


(* ========================================================================= *)
(* Phase 8 - ROUND31_S: ROUND31 with the UNION post the loop chain needs.      *)
(* Same ensures pc+0x10c6 -> pc+0x1156, post strengthened (purely additively)  *)
(* with state the next iteration's back-edge PRE consumes and ROUND31 leaves   *)
(* untouched: RDI = word_xor a b (the Maj a^b carry) and ring slots 1 (v1,     *)
(* stackptr+8) and 14 (v14, stackptr+112), which ROUND31's slot-15-only        *)
(* MAYCHANGE rides through unchanged.  union-gap discipline: never drop a       *)
(* conjunct the back-edge frame can't re-derive.                               *)
(* ========================================================================= *)
(* Phase 8 - SHA512 ROUND31_S: ROUND31 with the carried scratch the loop chain
   needs (the UNION post, union-gap discipline).  int64 clone of
   SHA256_BLOCK_NOHW_ROUND31_S.  Same ensures pc+0x10c6 -> pc+0x1156 but post
   strengthened (purely additively) with the state the next loop iteration's
   back-edge PRE consumes and ROUND31 leaves untouched:
     - RDI = word_xor a b : the Maj a^b carry threaded into the next round
       (ROUND31 recomputes RDI = its exit value, NOT w29 carried).
     - W-ring slots at stackptr+8 (v1, slot1) and stackptr+112 (v14, slot14):
       ROUND31's memory MAYCHANGE is only slot15 (stackptr+120), so 8 and 112
       ride through unchanged.
   These feed the continue-edge LOOPEDGE_CONT (which reads slots 1/14 for the
   next round's R12/R13/R15 scratch) and the next BODY15.

   Round 31 exit (odd): a=RBX,b=RCX,c=RDX,d=R8,e=R9,f=R10,g=R11,h=RAX roles.
   The asm exits with RDI = word_xor a b at orig 0x112f-0x1139:
     mov %rbx,%rdi ; xor %rcx,%rdi   (= a XOR b).  Confirmed in objdump. *)

let SHA512_BLOCK_NOHW_ROUND31_S = prove
 (`!pc K512 kb stackptr a b c d e f g h w16 w24 w29 w15 k31 v1 v14.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (stackptr:int64,128) (kb:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x10c6) /\
            read RBP s = kb /\ read RSP s = stackptr /\
            read R12 s = (w16:int64) /\
            read R13 s = word_ror (w16:int64) 7 /\
            read RDI s = (w29:int64) /\
            read R15 s = word_xor (b:int64) (c:int64) /\
            read (memory :> bytes64 kb) s = (k31:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 64))) s = w24 /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s = w15 /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = (v1:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = (v14:int64) /\
            read RBX s = (a:int64) /\ read RCX s = (b:int64) /\
            read RDX s = (c:int64) /\ read R8  s = (d:int64) /\
            read R9  s = (e:int64) /\ read R10 s = (f:int64) /\
            read R11 s = (g:int64) /\ read RAX s = (h:int64))
       (\s. read RIP s = word (pc + 0x1156) /\
            read RBP s = word_add kb (word 24) /\
            read RSP s = stackptr /\
            read RDI s = word_xor (a:int64) (b:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = v1 /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = v14 /\
            read RBX s = EL 1 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read RCX s = EL 2 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read RDX s = EL 3 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R8  s = EL 4 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R9  s = EL 5 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R10 s = EL 6 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R11 s = EL 7 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15))) /\
            read R14 s = sha512_hash_sigma_0 a /\
            read RAX s = word_sub (EL 0 (sha512_round [a;b;c;d;e;f;g;h] k31
              (word_add (word_add (sha512_msg_sigma_1 w29) w24)
                        (word_add (sha512_msg_sigma_0 w16) w15)))) (sha512_hash_sigma_0 a) /\
            read (memory :> bytes64 (word_add stackptr (word 120))) s =
              word_add (word_add (sha512_msg_sigma_1 w29) w24)
                       (word_add (sha512_msg_sigma_0 w16) w15))
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 120))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--42) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REWRITE_TAC[SHA512_SIGMA1_BRIDGE; SHA512_SIGMA0_BRIDGE;
              SHA512_CHOOSE_BRIDGE; SHA512_MAJ_BRIDGE;
              SHA512_MSG_SIGMA0_BRIDGE; SHA512_MSG_SIGMA1_BRIDGE] THEN
  REWRITE_TAC[sha512_round] THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;


(* ========================================================================= *)
(* Phase 8 - PROLOGUE: the 5-instruction back-edge transition the inner loop's *)
(* jne lands on (orig 0x71f..0x733), tmc pc+0x71b -> pc+0x72f.  Reconciles     *)
(* ROUND31's deferred-Sigma0 SPLIT (add %r14,%rax restores EL 0) and reloads   *)
(* the next sub-round's sigma scratch (slot1->R12/R13, slot14->R15).           *)
(* ========================================================================= *)
(* Phase 8 - SHA512 PROLOGUE: the 5-instruction back-edge transition the inner
   loop's `jne` lands on (orig 0x71f..0x733).  int64 clone of
   SHA256_BLOCK_NOHW_PROLOGUE.  Reconciles ROUND31's deferred-Sigma0 SPLIT state
   and reloads the next sub-round's sigma scratch.  No branch, no memory compare.
     pc+0x71b mov 0x8(%rsp),%r13    R13 := ring slot 1  (next sub-round v1)
     pc+0x720 mov 0x70(%rsp),%r15   R15 := ring slot 14 (next sub-round v14)
     pc+0x725 mov %r13,%r12         R12 := slot 1
     pc+0x728 ror $0x7,%r13         R13 := ror(slot1,7)
     pc+0x72c add %r14,%rax         RAX := rax_in + r14_in  (THE Sigma0 fold:
                                    ROUND31 exits RAX = EL0 - Sigma0(a) and
                                    R14 = Sigma0(a); this add restores EL0.)
   -> pc+0x72f (next round's clean entry, NOT executed here). *)

let SHA512_BLOCK_NOHW_PROLOGUE = prove
 (`!pc K512 stackptr rbp_val r1 r14v rax_in r14_in.
     nonoverlapping (word pc,4578) (stackptr:int64,128)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x71b) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = (rax_in:int64) /\
            read R14 s = (r14_in:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = (r1:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = (r14v:int64))
       (\s. read RIP s = word (pc + 0x72f) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read R12 s = (r1:int64) /\
            read R13 s = word_ror (r1:int64) 7 /\
            read R15 s = (r14v:int64) /\
            read RAX s = word_add (rax_in:int64) r14_in)
       (MAYCHANGE [RIP;RAX;R12;R13;R15] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--5) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;


(* ========================================================================= *)
(* Phase 8 - cmpb (:8 memory-operand CMP) stepper augmentation.                *)
(* X86_OPERATION_CLAUSES carries x86_CMP only at :64 and :32; the loop         *)
(* sentinel `cmpb $0,0x7(%rbp)` runs x86_CMP at :8.  Build the :8 clause the   *)
(* way x86.ml builds the others, append it, and re-evaluate the stepper chain  *)
(* VERBATIM under _C8 names.  Pure x86.ml machinery (no SHA-512 specifics);     *)
(* used only by the loop-edge lemmas below.                                    *)
(* ========================================================================= *)
let X86_CMP_8_CLAUSE =
  (CONV_RULE (TOP_DEPTH_CONV WORD_SIMPLE_SUBWORD_CONV) o
   CONV_RULE(TOP_DEPTH_CONV let_CONV) o SPEC_ALL)
  (INST_TYPE[`:8`,`:N`] x86_CMP);;

let X86_OPERATION_CLAUSES_C8 = X86_OPERATION_CLAUSES @ [X86_CMP_8_CLAUSE];;

let X86_CONV_C8 (decode_ths:thm option array) ths tm =
  (* Find `read RIP .. = ..` from ths (assumptions). *)
  let pc_th = try find
    (fun th ->
      let c = concl th in
      is_eq c && is_read_rip (fst (dest_eq c)))
    ths with _ ->
      failwith "X86_CONV_C8: can't find `read RIP .. = ..` from ths" in

  (* Find `bytes_loaded ..`. *)
  let bytes_loaded_mc_ths:thm list =
    (* Pick the _mc const from decode_ths, if decode_ths[0] != None, which is
       likely to be true. *)
    let the_mc:term option = Option.bind decode_ths.(0)
      (fun th ->
        (* th is `forall .., bytes_loaded ... _mc ==> x86_decode ..`. *)
        let t = concl th in
        let bytes_loaded_term = fst (dest_imp (snd (strip_forall t))) in
        let the_mc = last (snd (strip_comb bytes_loaded_term)) in
        (* if _mc contains relocations, the_mc is `.._mc args`. In this
           case, return None. *)
        if is_const the_mc then Some the_mc else None) in
    let bytes_loaded_tm = `bytes_loaded` in
    let res = filter (fun th ->
        let cc = concl th in is_comb cc && (
        let c,args = strip_comb (concl th) in
        c = bytes_loaded_tm &&
          (the_mc = None || last args = Option.get the_mc)))
      ths in
    if res = [] then failwith
        ("X86_CONV_C8: can't find `bytes_loaded .. .. " ^
          (if the_mc <> None then string_of_term (Option.get the_mc) else "..")
          ^ "` from ths")
    else res in

  let eth = tryfind (fun loaded_mc_th ->
      GEN_REWRITE_CONV I [X86_THM decode_ths loaded_mc_th pc_th] tm)
    bytes_loaded_mc_ths in
  (* Pick the right rules. It will be a singleton in most cases... *)
  let x86_execute_case_rules:thm list =
    let ts = find_terms is_const (concl eth) in
    List.filter_map (fun t ->
      try Some ((assoc (name_of t) X86_EXECUTE_CASES)) with _ -> None) ts in
  (K eth THENC
   PURE_ONCE_REWRITE_CONV(x86_execute_case_rules) THENC
   REWRITE_CONV[add_store_event;add_load_event;SEQ_ID] THENC
   ONCE_DEPTH_CONV OPERAND_SIZE_CONV THENC
   REWRITE_CONV[condition_semantics; aligned_OPERAND128; aligned_OPERAND256] THENC
   REWRITE_CONV[OPERAND_SIZE_CASES] THENC
   REWRITE_CONV[OPERAND_CLAUSES] THENC
   ONCE_DEPTH_CONV BSID_SEMANTICS_CONV THENC
   REWRITE_CONV X86_OPERATION_CLAUSES_C8 THENC
   REWRITE_CONV[READ_RVALUE;
                ASSIGN_ZEROTOP_32; READ_ZEROTOP_32; WRITE_ZEROTOP_32;
                ASSIGN_ZEROTOP_128; READ_ZEROTOP_128; WRITE_ZEROTOP_128;
                READ_BOTTOM_128] THENC
   DEPTH_CONV WORD_NUM_RED_CONV THENC
   REWRITE_CONV[SEQ; condition_semantics] THENC
   REWRITE_CONV[bytesize] THENC (* bytesize in add_{load,store}_event *)
   GEN_REWRITE_CONV TOP_DEPTH_CONV
    [UNDEFINED_VALUE; UNDEFINED_VALUES; SEQ_ID] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV
    [ASSIGNS_PULL_ZEROTOP_THM; ASSIGNS_PULL_THM] THENC
   REWRITE_CONV[ASSIGNS_THM] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV [SEQ_PULL_THM; BETA_THM] THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV[assign; seq; UNWIND_THM1; BETA_THM] THENC
   TRY_CONV(REWRITE_CONV[WRITE_BOTTOM_128]) THENC
   TRY_CONV(REWRITE_CONV READ_YMM_SSE_EQUIV) THENC
   REWRITE_CONV[] THENC REWRITE_CONV[WRITE_SHORT; READ_SHORT] THENC
   TOP_DEPTH_CONV COMPONENT_READ_OVER_WRITE_CONV THENC
   X86_FORCE_CONDITIONAL_CONV ths THENC
   ONCE_DEPTH_CONV
    (GEN_REWRITE_CONV I [GSYM WORD_ADD] THENC
     GEN_REWRITE_CONV (RAND_CONV o TOP_DEPTH_CONV) [GSYM ADD_ASSOC] THENC
     RAND_CONV NUM_REDUCE_CONV) THENC
   TOP_DEPTH_CONV COMPONENT_WRITE_OVER_WRITE_CONV THENC
   GEN_REWRITE_CONV (SUB_COMPONENTS_CONV o TOP_DEPTH_CONV) ths THENC
   GEN_REWRITE_CONV TOP_DEPTH_CONV [WORD_VAL] THENC
   ONCE_DEPTH_CONV WORD_PC_PLUS_CONV THENC
   DEPTH_CONV WORD_NUM_RED_CONV THENC
   ONCE_DEPTH_CONV NORMALIZE_RELATIVE_ADDRESS_CONV
 ) tm;;
let X86_BASIC_STEP_C8_TAC =
  let x86_tm = `x86` and x86_ty = `:x86state` and one = `1:num` in
  fun (decode_ths: thm option array) sname store_inst_term_to (asl,w) ->
    let sv = rand w and sv' = mk_var(sname,x86_ty) in
    let atm = mk_comb(mk_comb(x86_tm,sv),sv') in
    let eth = X86_CONV_C8 decode_ths (map snd asl) atm in

    (* store the decoded instruction at store_inst_term_to *)
    (match store_inst_term_to with
     | Some r -> r := rhs (concl eth)
     | None -> ());

    (* prepare a tactic for progressing to a next step. *)
    let progress_tac =
      let c,_ = strip_comb w in
      if name_of c = "eventually" then
        GEN_REWRITE_TAC I [eventually_CASES] THEN DISJ2_TAC
      else if name_of c = "eventually_n" then
        let stepn = dest_numeral(rand(rator(rator w))) in
        let stepn_decr = stepn -/ num 1 in
        (* stepn = 1+{stepn-1}*)
        let stepn_thm = GSYM (NUM_ADD_CONV
          (mk_binary "+" (one,mk_numeral(stepn_decr)))) in
        GEN_REWRITE_TAC (RATOR_CONV o RATOR_CONV o RAND_CONV) [stepn_thm] THEN
        GEN_REWRITE_TAC I [EVENTUALLY_N_STEP]
      else failwith "X86_BASIC_STEP_C8_TAC: neither eventually nor eventually_n"
      in

    (progress_tac THEN CONJ_TAC THENL
     [GEN_REWRITE_TAC BINDER_CONV [eth] THEN
      (CONV_TAC EXISTS_NONTRIVIAL_CONV ORELSE
        (PRINT_GOAL_TAC THEN
        FAIL_TAC ("X86_BASIC_STEP_C8_TAC: Equality between two states is " ^
                  "ill-formed. Did you forget to assume an extra condition" ^
                  " like pointer alignment?")));
      X_GEN_TAC sv' THEN GEN_REWRITE_TAC LAND_CONV [eth] THEN
      REPEAT X86_UNDEFINED_CHOOSE_TAC]) (asl,w);;
let X86_STEP_C8_TAC (mc_length_th,decode_ths) subths sname
      (store_inst_term_to: term ref option)
      (strip_component_tac: thm_tactic) =
  (*** This does the basic decoding setup ***)

  X86_BASIC_STEP_C8_TAC decode_ths sname store_inst_term_to THEN

  (*** This part shows the code isn't self-modifying ***)

  NONSELFMODIFYING_STATE_UPDATE_TAC
    (MATCH_MP bytes_loaded_update mc_length_th) THEN

  (*** Attempt also to show subroutines aren't modified, if applicable ***)

  MAP_EVERY (TRY o NONSELFMODIFYING_STATE_UPDATE_TAC o
    MATCH_MP bytes_loaded_update o CONJUNCT1) subths THEN

  (*** This part produces any updated versions of existing asms ***)

  ASSUMPTION_STATE_UPDATE_TAC THEN

  (*** Produce updated "MAYCHANGE" assumption ***)

  MAYCHANGE_STATE_UPDATE_TAC THEN

  (*** This adds state component theorems for the updates ***)
  (*** Could also assume th itself but I throw it away   ***)

  DISCH_THEN(fun th ->
    let thl = STATE_UPDATE_NEW_RULE th in
    if thl = [] then ALL_TAC else
    MP_TAC(end_itlist CONJ thl) THEN
    ASSEMBLER_SIMPLIFY_TAC THEN
    strip_component_tac th);;
let X86_VERBOSE_STEP_C8_TAC (exth1,exth2) sname g =
  Format.print_string("Stepping to state "^sname); Format.print_newline();
  X86_STEP_C8_TAC (exth1,exth2) [] sname None (K STRIP_TAC) g;;
let X86_SINGLE_STEP_C8_TAC th s =
  time (X86_VERBOSE_STEP_C8_TAC th s) THEN
  DISCARD_OLDSTATE_TAC s THEN
  CLARIFY_TAC;;
let X86_STEPS_C8_TAC th snums =
  MAP_EVERY (X86_SINGLE_STEP_C8_TAC th) (statenames "s" snums);;
(* ------------------------------------------------------------------------- *)
(* Phase 8 - the two inner-loop edges at the sentinel cmpb (pc+0x1156).        *)
(* CONTINUE (sb<>0): cmpb+jne -> pc+0x71b, then 5 prologue instrs -> pc+0x72f  *)
(*   (7 steps).  EXIT (sb=word 0): jne not taken, fall through to pc+0x1160    *)
(*   (2 steps).  Sentinel byte = TOP byte (+7) of next int64 K-word at rbp+7.  *)
(* Both step the byte compare with X86_STEPS_C8_TAC (the :8 CMP clause).       *)
(* ------------------------------------------------------------------------- *)

let SHA512_BLOCK_NOHW_LOOPEDGE_CONT = prove
 (`!pc K512 stackptr rbp_val r1 r14v rax_in r14_in sb.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (word pc,4578) (rbp_val:int64,8) /\
     ~(sb = word 0)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x1156) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = (rax_in:int64) /\
            read R14 s = (r14_in:int64) /\
            read (memory :> bytes8 (word_add rbp_val (word 7))) s = (sb:byte) /\
            read (memory :> bytes64 (word_add stackptr (word 8))) s = (r1:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 112))) s = (r14v:int64))
       (\s. read RIP s = word (pc + 0x72f) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read R12 s = (r1:int64) /\
            read R13 s = word_ror (r1:int64) 7 /\
            read R15 s = (r14v:int64) /\
            read RAX s = word_add (rax_in:int64) r14_in)
       (MAYCHANGE [RIP;RAX;R12;R13;R15] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA512_COMPRESS_EXEC (1--2) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[WORD_SUB_0; VAL_EQ_0]) THEN
  FIRST_X_ASSUM(fun th ->
    if can (term_match [] `read RIP s2 = X`) (concl th)
    then ASSUME_TAC(REWRITE_RULE[ASSUME `~(sb:byte = word 0)`] th)
    else NO_TAC) THEN
  X86_STEPS_C8_TAC SHA512_COMPRESS_EXEC (3--7) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;


let SHA512_BLOCK_NOHW_LOOPEDGE_EXIT = prove
 (`!pc K512 stackptr rbp_val rax_in r14_in.
     nonoverlapping (word pc,4578) (stackptr:int64,128) /\
     nonoverlapping (word pc,4578) (rbp_val:int64,8)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc K512) /\
            read RIP s = word (pc + 0x1156) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = (rax_in:int64) /\
            read R14 s = (r14_in:int64) /\
            read (memory :> bytes8 (word_add rbp_val (word 7))) s = (word 0:byte))
       (\s. read RIP s = word (pc + 0x1160) /\
            read RBP s = rbp_val /\ read RSP s = stackptr /\
            read RAX s = (rax_in:int64) /\
            read R14 s = (r14_in:int64))
       (MAYCHANGE [RIP] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_C8_TAC SHA512_COMPRESS_EXEC (1--2) THEN
  RULE_ASSUM_TAC(REWRITE_RULE[WORD_SUB_0; VAL_EQ_0]) THEN
  FIRST_X_ASSUM(fun th ->
    if can (term_match [] `read RIP s2 = X`) (concl th)
    then ASSUME_TAC(REWRITE_RULE[] th)
    else NO_TAC) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[]);;


(* ========================================================================= *)
(* Phase 8 - ROUND31_S_ABS: ROUND31_S restated over the OPAQUE compress_rounds *)
(* state.  Working state becomes sha512_compress_rounds m sin {31,32} and the  *)
(* message words sha512_msg_schedule m {16,24,29,15} (iteration-0 ring, EL j m *)
(* at the schedule base).  Folds a SINGLE round (31 -> 32); the SPLIT exit is  *)
(* preserved verbatim (RAX = EL 0 (cr 32) - Sigma0(EL 0 (cr 31)), R14 = that   *)
(* Sigma0).  Programmatic SPECL of ROUND31_S, same idiom as BODY15_ABS.        *)
(* ========================================================================= *)
(* Phase 8 - ROUND31_S_ABS: ROUND31_S restated over the OPAQUE compress_rounds
   state.  int64 clone of SHA256_BLOCK_NOHW_ROUND31_S_ABS.  The 16th sub-round
   (round 31) of one rounds_16_xx iteration, restated so its pre/post working
   state is sha512_compress_rounds m sin {31,32} rather than the explicit nested
   sha512_round term, and its message words are sha512_msg_schedule m {16,24,29,15}
   for the ITERATION-0 ring (EL j m at the schedule base).  Folds a SINGLE round
   (31 -> 32).  The deliberate SPLIT exit is preserved verbatim:
     RAX = EL 0 (cr m sin 32) - Sigma0 (EL 0 (cr m sin 31)),
     R14 = Sigma0 (EL 0 (cr m sin 31))
   (the next iteration's prologue folds R14 into RAX to recover EL 0 cr 32).
   The v1/v14 ring slots and RDI = a^b carry ride through unchanged, feeding
   LOOPEDGE_CONT and the next BODY15.  DERIVED from ROUND31_S by instantiating
   a..h := EL j (cr m sin 31), message words := sched terms, k31 := EL 31 c. *)

let SHA512_BLOCK_NOHW_ROUND31_S_ABS =
  (* schedule memo over abstract m (EL t m at the base, no length hyp). *)
  let tt_tm = `t:num` in
  let msched_pat = `sha512_msg_schedule m t` in
  let instM t = vsubst [mk_small_numeral t,tt_tm] msched_pat in
  let schedM = Array.make 64 TRUTH in
  (for t = 0 to 15 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(RATOR_CONV(RATOR_CONV(RAND_CONV NUM_LT_CONV)) THENC
                           REWRITE_CONV[COND_CLAUSES] THENC
                           TRY_CONV(LAND_CONV NUM_RED_CONV)))
         (REWR_CONV sha512_msg_schedule (instM t))
   done;
   for t = 16 to 31 do
     schedM.(t) <-
       CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
           REWRITE_CONV[schedM.(t-2); schedM.(t-7); schedM.(t-15); schedM.(t-16)]))
         (REWR_CONV sha512_msg_schedule (instM t))
   done);
  (* single-round fold: cr m sin 32 = sha512_round (cr m sin 31)(EL 31 c)(sched 31). *)
  let round31_fold_m = (COMPRESS_ROUNDS_DOWNTO 31) `sha512_compress_rounds m sin 32` in
  (* [EL 0 sin31;..;EL 7 sin31] = sin31, under LENGTH sin = 8. *)
  let sin31_len = prove
   (`LENGTH (sin:int64 list) = 8
       ==> [EL 0 (sha512_compress_rounds m sin 31);
            EL 1 (sha512_compress_rounds m sin 31);
            EL 2 (sha512_compress_rounds m sin 31);
            EL 3 (sha512_compress_rounds m sin 31);
            EL 4 (sha512_compress_rounds m sin 31);
            EL 5 (sha512_compress_rounds m sin 31);
            EL 6 (sha512_compress_rounds m sin 31);
            EL 7 (sha512_compress_rounds m sin 31)]
           = sha512_compress_rounds m sin 31`,
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA512_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  (* instantiate ROUND31_S (19 binders: pc K512 kb stackptr a..h                *)
  (*   w16 w24 w29 w15 k31 v1 v14).  kdat:num for the rodata slot, NOT `K512`.   *)
  let inst_args =
    [`pc:num`; `kdat:num`; `kb:int64`; `stackptr:int64`] @
    (map (fun j -> vsubst [mk_small_numeral j,`j:num`]
                    `EL j (sha512_compress_rounds m sin 31):int64`) (0--7)) @
    [ rhs(concl schedM.(16)); rhs(concl schedM.(24));
      rhs(concl schedM.(29)); rhs(concl schedM.(15));
      `EL 31 sha512_constants:int64`; `v1:int64`; `v14:int64` ] in
  let r31s_inst = SPECL inst_args SHA512_BLOCK_NOHW_ROUND31_S in
  let th0 = DISCH `LENGTH (sin:int64 list) = 8` r31s_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sin31_len; GSYM schedM.(31); GSYM round31_fold_m]
    (UNDISCH th0)));;



(* ========================================================================= *)
(* Phase 8 (cont.) - per-iteration ABS composition: the inner-loop iteration  *)
(* lemmas over the OPAQUE compress_rounds / sched abstraction.  int64 port of  *)
(* the SHA-256 MK_BODY15_ABS / MK_ROUND31S_ABS / MK_BR_S_ABS / MK_ITER_ABS /   *)
(* MK_ITER_ABS_EXIT generators (sha256_compress.ml ~L5117-6188).               *)
(*                                                                            *)
(* Each iteration is BODY15 (15 clean sub-rounds) then ROUND31_S (the 16th,    *)
(* SPLIT exit).  Iterations are NOT identical: iteration i consumes the W-ring *)
(* holding sched m (16i+j) (j=0..15) and produces sched m (16i+16+j), while    *)
(* the working state advances cr m sin (16+16i) -> cr m sin (32+16i).  Because *)
(* the message-schedule sigma-expansion is SHIFT-INVARIANT, the committed      *)
(* BODY15 / ROUND31_S (over free ring vars vj and free working a..h) restate   *)
(* to iteration i by instantiating vj := sched m (16i+j) and a..h := EL j      *)
(* (cr m sin (16+16i)), then folding (SHA-256 session-024: the seam matches    *)
(* atom-for-atom ONLY because MK_ROUND31S_ABS instantiates w16/w24/w29/w15      *)
(* with the OPAQUE sched atoms MK_BODY15_ABS's POST exposes, not expanded      *)
(* sigma-trees).  4 iterations (i=0,1,2 continue; i=3 exit), not SHA-256's 3.  *)
(*                                                                            *)
(* MK_BR_S_ABS i       : body i ; round31s i, pc+0x72f -> pc+0x1156 (SPLIT).   *)
(* MK_ITER_ABS i br     : br ; LOOPEDGE_CONT, pc+0x72f -> pc+0x72f (continue).  *)
(* MK_ITER_ABS_EXIT i br: br ; LOOPEDGE_EXIT, pc+0x72f -> pc+0x1160 (exit).     *)
(* All composed PROGRAMMATICALLY by term surgery; the LCF kernel is the seam-  *)
(* soundness oracle (a mismatched seam makes ENSURES_SEQUENCE_TAC FAIL).       *)
(* ========================================================================= *)
(* ---- shared term builders (literal-index instantiation) ---- *)
let abs_cr_tm n =       (* sha512_compress_rounds m sin <n> *)
  vsubst [mk_small_numeral n,`n:num`] `sha512_compress_rounds m sin n`;;
let abs_el_cr j n =     (* EL <j> (sha512_compress_rounds m sin <n>) : int64 *)
  vsubst [mk_small_numeral j,`j:num`; mk_small_numeral n,`n:num`]
    `EL j (sha512_compress_rounds m sin n):int64`;;
let abs_el_k t =        (* EL <t> sha512_constants : int64 *)
  vsubst [mk_small_numeral t,`t:num`] `EL t sha512_constants:int64`;;
let abs_instM t =       (* sha512_msg_schedule m <t> *)
  vsubst [mk_small_numeral t,`t:num`] `sha512_msg_schedule m t`;;

(* shifted-window schedule memo: leaves [rb,rb+15] opaque (REFL), expand        *)
(* [rb+16,hi] via the recurrence (literal indices -> NUM_RED_CONV).             *)
let abs_build_schedM rb hi =
  let memo = Array.make (hi+1) TRUTH in
  for t = rb to min hi (rb+15) do memo.(t) <- REFL (abs_instM t) done;
  for t = rb+16 to hi do
    memo.(t) <-
      CONV_RULE(RAND_CONV(DEPTH_CONV NUM_RED_CONV THENC
          REWRITE_CONV[memo.(t-2); memo.(t-7); memo.(t-15); memo.(t-16)]))
        (REWR_CONV sha512_msg_schedule (abs_instM t));
  done;
  memo;;

(* MK_BODY15_ABS i : BODY15 for inner-loop iteration i, W-ring stores folded     *)
(* to opaque sched m (16i+16+j) (clean form).                                    *)
let MK_BODY15_ABS i =
  let rb = 16*i and wb = 16+16*i in
  let schedM = abs_build_schedM rb (wb+14) in
  let foldeq = prove
   (mk_eq(abs_cr_tm (wb+15),
          rhs(concl((COMPRESS_ROUNDS_DOWNTO wb THENC
                     REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))
                    (abs_cr_tm (wb+15))))),
    CONV_TAC(LAND_CONV(COMPRESS_ROUNDS_DOWNTO wb THENC
                       REWRITE_CONV(map (fun t -> schedM.(t)) (wb--(wb+14))))) THEN
    REFL_TAC) in
  let sinwb = abs_cr_tm wb in
  let sinwb_len = prove
   (mk_imp(`LENGTH (sin:int64 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j wb) (0--7),`:int64`), sinwb)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA512_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kbase:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j wb) (0--7)) @
    (map (fun j -> abs_instM (rb+j)) (0--15)) @
    (map (fun t -> abs_el_k (wb+t)) (0--14)) in
  let body15_inst = SPECL inst_args SHA512_BLOCK_NOHW_BODY15 in
  let th0 = DISCH `LENGTH (sin:int64 list) = 8` body15_inst in
  let raw = GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwb_len; GSYM foldeq] (UNDISCH th0))) in
  REWRITE_RULE (map (fun t -> GSYM schedM.(t)) ((rb+16)--(wb+14))) raw;;

(* ONE-LEVEL expansion of sched m t : leaves the four sub-scheds m {t-2,t-7,     *)
(* t-15,t-16} OPAQUE.  Used by MK_ROUND31S_ABS so its PRE references the same    *)
(* opaque sched atoms that MK_BODY15_ABS's POST exposes (atom-for-atom seam).    *)
let abs_one_level t =
  CONV_RULE(RAND_CONV(
      RATOR_CONV(RATOR_CONV(RAND_CONV NUM_RED_CONV)) THENC
      REWRITE_CONV[COND_CLAUSES] THENC
      DEPTH_CONV NUM_RED_CONV))
    (REWR_CONV sha512_msg_schedule (abs_instM t));;

(* MK_ROUND31S_ABS i : ROUND31_S for iteration i (single round 31+16i ->         *)
(* 32+16i, SPLIT exit).  Stores opaque sched m (16i+31).  message-word binders   *)
(* w16/w24/w29/w15 := OPAQUE sched atoms (session-024 fix), NOT expanded trees.  *)
let MK_ROUND31S_ABS i =
  let rb = 16*i and wb = 16+16*i in
  let ol = abs_one_level (rb+31) in
  let foldeq = (COMPRESS_ROUNDS_DOWNTO (wb+15)) (abs_cr_tm (wb+16)) in
  let sinwbp15 = abs_cr_tm (wb+15) in
  let sinwbp15_len = prove
   (mk_imp(`LENGTH (sin:int64 list) = 8`,
           mk_eq(mk_list(map (fun j -> abs_el_cr j (wb+15)) (0--7),`:int64`), sinwbp15)),
    DISCH_TAC THEN MATCH_MP_TAC EL8_RECONSTRUCT THEN
    MATCH_MP_TAC LENGTH_SHA512_COMPRESS_ROUNDS THEN ASM_REWRITE_TAC[]) in
  let inst_args =
    [`pc:num`; `kdat:num`; `kb:int64`; `stackptr:int64`] @
    (map (fun j -> abs_el_cr j (wb+15)) (0--7)) @
    [ abs_instM (rb+16); abs_instM (rb+24); abs_instM (rb+29); abs_instM (rb+15);
      abs_el_k (wb+15); `v1:int64`; `v14:int64` ] in
  let r31s_inst = SPECL inst_args SHA512_BLOCK_NOHW_ROUND31_S in
  let th0 = DISCH `LENGTH (sin:int64 list) = 8` r31s_inst in
  GEN_ALL (DISCH_ALL (REWRITE_RULE
    [UNDISCH sinwbp15_len; GSYM ol; GSYM foldeq]
    (UNDISCH th0)));;

(* ---- shared plumbing for the composers ---- *)
let rec strip_all_imp tm = if is_imp tm then strip_all_imp (snd(dest_imp tm)) else tm;;
let parts th =
  let vs = fst(strip_forall(concl th)) in
  let bod = snd(strip_forall(concl th)) in
  let rec hyps tm = if is_imp tm then let h,r = dest_imp tm in
                      let hs,e = hyps r in (h::hs,e) else ([],tm) in
  let hs,ens = hyps bod in
  let l,c = dest_comb ens in let l2,q = dest_comb l in
  let _,p = dest_comb l2 in (vs,hs,p,q,c);;
let conjs_of_lam q = let s,body = dest_abs q in s, conjuncts body;;
let comp_of c = let l,_ = dest_eq c in snd(dest_comb(fst(dest_comb l)));;
let comp_str c = try string_of_term (comp_of c) with _ -> "?";;
let rhs_of c = snd(dest_eq c);;
let by_comp t lst = find (fun c -> comp_str c = t) lst;;
let is_named nm c =
  try let cn = fst(dest_const(fst(strip_comb c))) in cn = nm with _ -> false;;
let seqop = `(,,):(x86state->x86state->bool)->(x86state->x86state->bool)->
                  (x86state->x86state->bool)`;;
let ens_head_of th =
  let ens = strip_all_imp (snd(strip_forall(concl th))) in
  rator(rator(rator ens));;
let mk_ensures eh p q c = mk_comb(mk_comb(mk_comb(eh,p),q),c);;
let goal_rodata_var w =
  let blob = find_term (fun t ->
      (try fst(dest_const(fst(strip_comb t)))="sha512_compress_tmc"
       with _ -> false)) w in
  last (snd (strip_comb blob));;
let execup = MATCH_MP bytes_loaded_update (fst SHA512_COMPRESS_EXEC);;

(* ===================================================================== *)
(* MK_BR_S_ABS i : compose body i ; round31s i at pc+0x10c6.              *)
(* ===================================================================== *)
let MK_BR_S_ABS i =
  let bI = MK_BODY15_ABS i and rI = MK_ROUND31S_ABS i in
  let (bvars,bhyps,pBlam,qBlam,cB) = parts bI in
  let (rvars,rhypsB,pR,qR,cR)  = parts rI in
  ignore rhypsB;
  let sB, pBc = conjs_of_lam pBlam in
  let _, qBc  = conjs_of_lam qBlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let rv = vbn rvars in
  (* seam instantiation: ABS lemmas pre-align a..h; only kb/v1/v14 are free.    *)
  (* int64: bare values, no word_zx strip.                                       *)
  let rbp_b  = rhs_of(by_comp "RBP" qBc) in                 (* kbase+232 *)
  let slot8  = rhs_of(by_comp "memory :> bytes64 (word_add stackptr (word 8))" qBc) in
  let slot112= rhs_of(by_comp "memory :> bytes64 (word_add stackptr (word 112))" qBc) in
  let inst = [ rbp_b, rv"kb"; slot8, rv"v1"; slot112, rv"v14" ] in
  let pR_i = vsubst inst pR and qR_i = vsubst inst qR and cR_i = vsubst inst cR in
  let _, pR_i_c = conjs_of_lam pR_i in
  let _, qR_i_c = conjs_of_lam qR_i in
  (* B15-post ring slots NOT in ROUND31_S frame (everything but slot120): survive *)
  let surviving_slots = filter (fun off -> off <> 120)
                          [0;8;16;24;32;40;48;56;64;72;80;88;96;104;112] in
  let body_slot_conj off = by_comp
      (if off = 0 then "memory :> bytes64 stackptr"
       else "memory :> bytes64 (word_add stackptr (word "^string_of_int off^"))") qBc in
  let carried_slot_conjs = map body_slot_conj surviving_slots in
  (* carried K read at kbase+232 = EL (31+16i) consts (k31), which B15 post lacks. *)
  let k31val = abs_el_k (16+16*i+15) in   (* EL (31+16i) sha512_constants *)
  let kread232 = mk_eq(
     mk_comb(mk_comb(`read:(x86state,int64)component->x86state->int64`,
                     `memory :> bytes64 (word_add (kbase:int64) (word 232))`),
             sB), k31val) in
  let pre_lam  = mk_abs(sB, list_mk_conj (pBc @ [kread232])) in
  let frame = mk_comb(mk_comb(seqop,cB),cR_i) in
  let hyps_B = list_mk_conj bhyps in
  let no_extra = `nonoverlapping (stackptr:int64,128) (word_add (kbase:int64) (word 232),8)` in
  let hyps = mk_conj(hyps_B, no_extra) in
  let eh = ens_head_of bI in
  let post_lam = mk_abs(sB, list_mk_conj (qR_i_c @ carried_slot_conjs)) in
  let lensin = `LENGTH (sin:int64 list) = 8` in
  let comp_concl =
    list_mk_forall(bvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pR_i_c in
  let extra_seam_slots = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) carried_slot_conjs in
  let seamQ = mk_abs(sB, list_mk_conj (seamQ_conjs @ extra_seam_slots)) in
  let pc_seam = `pc + 0x10c6` in
  let body_self = SPECL bvars bI in
  let round31_seam =
    SPECL [ `kdat:num`; `pc:num`; rbp_b; slot8; slot112; `sin:int64 list`;
            `m:int64 list`; `stackptr:int64` ] rI in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg body_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg round31_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

let MK_ITER_ABS i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsC,pC,qC,cC) = parts SHA512_BLOCK_NOHW_LOOPEDGE_CONT in
  ignore chypsC;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rhs_of(by_comp "RAX" qBRc) in
  let r14_in_v  = rhs_of(by_comp "R14" qBRc) in
  let r1_v      = rhs_of(by_comp "memory :> bytes64 (word_add stackptr (word 8))" qBRc) in
  let r14v_v    = rhs_of(by_comp "memory :> bytes64 (word_add stackptr (word 112))" qBRc) in
  let sb_v = `sb:byte` in
  let cinst =
   [ `kdat:num`, cv"K512"; rbp_val_v, cv"rbp_val"; r1_v, cv"r1"; r14v_v, cv"r14v";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in"; sb_v, cv"sb" ] in
  let pC_i = vsubst cinst pC and qC_i = vsubst cinst qC and cC_i = vsubst cinst cC in
  let _, pC_i_c = conjs_of_lam pC_i in
  let _, qC_i_c = conjs_of_lam qC_i in
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_C = find is_bytes8 pC_i_c in
  let sent_state = rand(fst(dest_eq sent_read_C)) in
  let sent_read = subst [sBR, sent_state] sent_read_C in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  let cont_post_comps = map comp_str qC_i_c in
  let overwritten = ["RIP";"RAX";"R12";"R13";"R15"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) cont_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qC_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cC_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4578) (RBPV:int64,8)` in
  let sb_ne = mk_neg(mk_eq(sb_v,`word 0:byte`)) in
  (* sentinel nonoverlap: (stackptr,128) vs (rbp_val+7, 1) *)
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,128) (word_add (RBPV:int64) (word 7),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; sb_ne; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int64 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pC_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 0x1156` in
  let brs_self = SPECL brvars brI in
  let cont_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v; r1_v; r14v_v;
            rax_in_v; r14_in_v; sb_v ] SHA512_BLOCK_NOHW_LOOPEDGE_CONT in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg cont_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;

(* MK_ITER_ABS_EXIT i (brI) : compose BR_S_ABS i ; LOOPEDGE_EXIT at pc+0x1156    *)
(* (exit iteration: pc+0x72f -> pc+0x1160).  Sentinel byte = word 0.             *)
let MK_ITER_ABS_EXIT i brI =
  let (brvars,brhyps,pBRlam,qBRlam,cBR) = parts brI in
  let (cvars,chypsE,pE,qE,cE) = parts SHA512_BLOCK_NOHW_LOOPEDGE_EXIT in
  ignore chypsE;
  let sBR, pBRc = conjs_of_lam pBRlam in
  let _, qBRc = conjs_of_lam qBRlam in
  let vbn vs n = find (fun v -> name_of v = n) vs in
  let cv = vbn cvars in
  let rbp_val_v = rhs_of(by_comp "RBP" qBRc) in
  let rax_in_v  = rhs_of(by_comp "RAX" qBRc) in
  let r14_in_v  = rhs_of(by_comp "R14" qBRc) in
  let einst =
   [ `kdat:num`, cv"K512"; rbp_val_v, cv"rbp_val";
     rax_in_v, cv"rax_in"; r14_in_v, cv"r14_in" ] in
  let pE_i = vsubst einst pE and qE_i = vsubst einst qE and cE_i = vsubst einst cE in
  let _, pE_i_c = conjs_of_lam pE_i in
  let _, qE_i_c = conjs_of_lam qE_i in
  let is_bytes8 c =
    try let _ = find_term (fun t->is_const t && fst(dest_const t)="bytes8") c in true with _->false in
  let sent_read_E = find is_bytes8 pE_i_c in
  let sent_state = rand(fst(dest_eq sent_read_E)) in
  let sent_read = subst [sBR, sent_state] sent_read_E in
  let pre_lam = mk_abs(sBR, list_mk_conj (pBRc @ [sent_read])) in
  let exit_post_comps = map comp_str qE_i_c in
  let overwritten = ["RIP"] in
  let surviving = filter (fun c ->
       not(mem (comp_str c) exit_post_comps) && not(mem (comp_str c) overwritten)) qBRc in
  let post_lam = mk_abs(sBR, list_mk_conj (qE_i_c @ surviving)) in
  let frame = mk_comb(mk_comb(seqop,cBR),cE_i) in
  let hyps_BR = list_mk_conj brhyps in
  let no_rbp = vsubst [rbp_val_v,`RBPV:int64`] `nonoverlapping (word pc,4578) (RBPV:int64,8)` in
  let no_sent = vsubst [rbp_val_v,`RBPV:int64`]
      `nonoverlapping (stackptr:int64,128) (word_add (RBPV:int64) (word 7),1)` in
  let hyps = list_mk_conj [hyps_BR; no_rbp; no_sent] in
  let eh = ens_head_of brI in
  let lensin = `LENGTH (sin:int64 list) = 8` in
  let comp_concl =
    list_mk_forall(brvars,
      mk_imp(lensin, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame))) in
  let seamQ_conjs = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") pE_i_c in
  let extra_seam = filter (fun c -> not(mem (comp_str c) (map comp_str seamQ_conjs))) surviving in
  let seamQ = mk_abs(sBR, list_mk_conj (seamQ_conjs @ extra_seam)) in
  let pc_seam = `pc + 0x1156` in
  let brs_self = SPECL brvars brI in
  let exit_seam =
    SPECL [ `pc:num`; `kdat:num`; `stackptr:int64`; rbp_val_v;
            rax_in_v; r14_in_v ] SHA512_BLOCK_NOHW_LOOPEDGE_EXIT in
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  prove
   (comp_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN DISCH_TAC THEN STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
    [ match_leg brs_self THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[];
      match_leg exit_seam THEN sublem_a "s" "s'" THEN ASM_REWRITE_TAC[] ]);;


(* The four concrete inner-loop iteration lemmas (i=0,1,2 continue; i=3 exit). *)
let SHA512_BLOCK_NOHW_ITER_ABS_0 = MK_ITER_ABS 0 (MK_BR_S_ABS 0);;
let SHA512_BLOCK_NOHW_ITER_ABS_1 = MK_ITER_ABS 1 (MK_BR_S_ABS 1);;
let SHA512_BLOCK_NOHW_ITER_ABS_2 = MK_ITER_ABS 2 (MK_BR_S_ABS 2);;
let SHA512_BLOCK_NOHW_ITER_ABS_EXIT_3 = MK_ITER_ABS_EXIT 3 (MK_BR_S_ABS 3);;

(* ========================================================================= *)
(* Phase 9 - the single-block inner-loop lemma SHA512_BLOCK_NOHW_INNER.       *)
(*                                                                           *)
(*   HEAD16_ABS (pc+0x6b -> pc+0x72f) ; ITER_ABS_0[K+256] ; ITER_ABS_1[K+512] *)
(*   ITER_ABS_2[K+768] ; ITER_ABS_EXIT_3[K+1024]                             *)
(*     => ensures  pc+0x6b -> pc+0x1160                                       *)
(*   with working state  sha512_compress_rounds m [a;..;h] 80.                *)
(*                                                                           *)
(* The four iterations run the inner do-while loop body exactly 4 times       *)
(* (i=0,1,2 take the back-edge: sentinel byte != 0; i=3 exits: sentinel = 0). *)
(* NOTE: 4 iterations, not SHA-256's 3 (SHA-512 = 80 rounds = 16 head + 4*16).*)
(* Composed PROGRAMMATICALLY at each pc+0x72f seam by ENSURES_SEQUENCE_TAC     *)
(* with the per-iteration ABS lemmas reused verbatim: leg A = the accumulated *)
(* chain (its rodata binder kdat BOUND, so a plain MP_TAC), leg B = the        *)
(* appended ITER lemma (free kdat -> match_leg INST to the goal's own rodata   *)
(* var). seamQ = the appended lemma's PRE (minus the ENSURES_SEQUENCE-injected *)
(* bytes_loaded + RIP), so leg B closes with the trimmed sublem_b; leg A       *)
(* reconciles the seam:                                                        *)
(*  - entry seam (HEAD16->IT0): the W-ring is EL j m in HEAD16 POST vs          *)
(*    sched m j in IT0 PRE for j<16 -> bridge with SCHED_LT16_CONV; RDI Maj     *)
(*    carry matches directly (both word_xor (EL 1/2 (cr m [a..h] 16))).         *)
(*  - iter-to-iter seam: RBP (nested word_add of constant offsets) and RAX      *)
(*    (word_add (word_sub X sigma0) sigma0 = X) close by WORD_RULE; the R12/    *)
(*    R13/R15 ring + ring slots match directly (schedule SHIFT baked into the   *)
(*    ITER lemmas); RDI rotates EL 1/2 (cr .. (n+1)) = EL 0/1 (cr .. n) ->       *)
(*    CR_ROT1/CR_ROT2 at rounds 31/47/63.                                       *)
(* Anti-explosion holds: the chain grows LINEARLY (hyps accumulate as one flat  *)
(* conjunction); proved hyp-free under a single cold load (S011).               *)
(* ========================================================================= *)

(* EL 1/2 of one more compression round = EL 0/1 of the previous state:        *)
(* the next iteration's RDI Maj-carry (word_xor (EL1 crN) (EL2 crN)) equals     *)
(* the prior iteration's exit RDI (word_xor (EL0 cr(N-1)) (EL1 cr(N-1))).       *)
let CR_ROT1 = prove
 (`!m s n. EL 1 (sha512_compress_rounds m s (SUC n)) =
           EL 0 (sha512_compress_rounds m s n)`,
  REWRITE_TAC[COMPRESS_ROUNDS_SUC; sha512_round] THEN
  REPEAT GEN_TAC THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REFL_TAC);;

let CR_ROT2 = prove
 (`!m s n. EL 2 (sha512_compress_rounds m s (SUC n)) =
           EL 1 (sha512_compress_rounds m s n)`,
  REWRITE_TAC[COMPRESS_ROUNDS_SUC; sha512_round] THEN
  REPEAT GEN_TAC THEN CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REFL_TAC);;

(* literal-index instances:  EL 1 (cr m [a..h] (n+1)) = EL 0 (cr m [a..h] n)   *)
(* and EL 2 (..)= EL 1 (..) , via  n+1 = SUC n  (num_CONV).                     *)
let cr_rot_rules n =
  let suc = num_CONV (mk_small_numeral (n+1)) in
  let mk th = REWRITE_RULE[GSYM suc]
      (SPECL [`m:int64 list`;`[a;b;c;d;e;f;g;h]:int64 list`;mk_small_numeral n] th) in
  [mk CR_ROT1; mk CR_ROT2];;

let SHA512_BLOCK_NOHW_INNER =
  let len8 = LENGTH_CONV `LENGTH ([a;b;c;d;e;f;g;h]:int64 list)` in
  (* per-iteration ITER lemmas, instantiated for the chain.  SHA-512 K-base      *)
  (* advances +256/iter (16 rounds * 16-byte doubled-row stride).  sin:=[a..h] so *)
  (* the working state threads as cr m [a..h] (16i) directly.  Sentinel sb left   *)
  (* as a free binder for the continue iterations (rides the chain PRE).          *)
  (* SHA-512 ITER binder order: kdat pc kbase sin m stackptr.                      *)
  (* The three continue-sentinels read DISTINCT K512 top-bytes (0x27/0x19/0xca,    *)
  (* verified vs objdump); bake them concretely (SHA-256 pattern) so the composed   *)
  (* INNER carries NO free `sb` and is directly dischargeable against the concrete  *)
  (* K512 bytelist in Phase 10.  it3i (EXIT) already pins word 0 from LOOPEDGE_EXIT. *)
  let it0i = REWRITE_RULE[len8] (INST [`word 0x27:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 256)`;
              `[a;b;c;d;e;f;g;h]:int64 list`;`m:int64 list`;`stackptr:int64`]
             SHA512_BLOCK_NOHW_ITER_ABS_0)) in
  let it1i = REWRITE_RULE[len8] (INST [`word 0x19:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 512)`;
              `[a;b;c;d;e;f;g;h]:int64 list`;`m:int64 list`;`stackptr:int64`]
             SHA512_BLOCK_NOHW_ITER_ABS_1)) in
  let it2i = REWRITE_RULE[len8] (INST [`word 0xca:byte`,`sb:byte`]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 768)`;
              `[a;b;c;d;e;f;g;h]:int64 list`;`m:int64 list`;`stackptr:int64`]
             SHA512_BLOCK_NOHW_ITER_ABS_2)) in
  let it3i = REWRITE_RULE[len8]
      (SPECL [`kdat:num`;`pc:num`;`word_add (kbase:int64) (word 1024)`;
              `[a;b;c;d;e;f;g;h]:int64 list`;`m:int64 list`;`stackptr:int64`]
             SHA512_BLOCK_NOHW_ITER_ABS_EXIT_3) in
  (* leg-B trimmed SUBLEM (canned ENSURES_SUBLEMMA_TAC body minus the leg-1      *)
  (* branch, which auto-closes when seamQ = the appended lemma's PRE exactly).   *)
  let sublem_b_tac =
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC)] in
  (* compose prevThm ; itI at the pc+0x72f seam.                                 *)
  let compose_step prevThm itI legA_reconcile =
    let (pvars,phyps,pPlam,pQlam,pC) = parts prevThm in
    let (_,ihyps,iPlam,iQlam,iC) = parts itI in
    let sP, pPc = conjs_of_lam pPlam in
    let _,  pQc = conjs_of_lam pQlam in
    let sI, iPc0 = conjs_of_lam iPlam in
    let iPc = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c <> "RIP") iPc0 in
    let pcomps = map comp_str pQc in
    let carried_I = filter (fun c -> not(mem (comp_str c) pcomps)) iPc in
    let carried_P = map (vsubst [sP, sI]) carried_I in
    let pre_lam = mk_abs(sP, list_mk_conj (pPc @ carried_P)) in
    let post_lam = iQlam in
    let frame = mk_comb(mk_comb(seqop,pC),iC) in
    let hyps = list_mk_conj (phyps @ ihyps) in
    let eh = ens_head_of prevThm in
    let comp_concl = list_mk_forall(pvars, mk_imp(hyps, mk_ensures eh pre_lam post_lam frame)) in
    let seamQ = mk_abs(sI, list_mk_conj iPc) in
    let pc_seam = `pc + 0x72f` in
    let prev_self = SPECL pvars prevThm in
    let match_leg lemma =
      W(fun (asl,w) -> ignore asl;
          let kv = goal_rodata_var w in
          MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
          ASM_REWRITE_TAC[]) in
    let sublem_a = ENSURES_SUBLEMMA_TAC execup in
    let legA = MP_TAC (REWRITE_RULE[SOME_FLAGS] prev_self) THEN ASM_REWRITE_TAC[] in
    prove
     (comp_concl,
      REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN STRIP_TAC THEN
      ENSURES_SEQUENCE_TAC pc_seam seamQ THEN CONJ_TAC THENL
      [ legA THEN sublem_a "s" "s'" THEN legA_reconcile;
        match_leg itI THEN sublem_b_tac THEN ASM_REWRITE_TAC[] ]) in
  let SCHED_LT16_RULES = map (fun j -> SCHED_LT16_CONV (abs_instM j)) (0--15) in
  let c0 = compose_step SHA512_BLOCK_NOHW_HEAD16_ABS it0i
             (REWRITE_TAC SCHED_LT16_RULES THEN ASM_REWRITE_TAC[]) in
  let c1 = compose_step c0 it1i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 31) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  let c2 = compose_step c1 it2i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 47) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  let c3 = compose_step c2 it3i
             (ASM_REWRITE_TAC[] THEN REWRITE_TAC (cr_rot_rules 63) THEN
              REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE) in
  c3;;

(* ========================================================================= *)
(* Phase 10 - single block:  ENTRY ; INNER ; TAIL = sha512_block.            *)
(*                                                                           *)
(* INNER (above) runs the 16 head rounds + 4 inner-loop iterations            *)
(* (pc+0x6b -> pc+0x1160) leaving the working state in the SPLIT form         *)
(* (RAX = EL0(cr 80) - sigma0(EL0(cr 79)), R14 = sigma0(EL0(cr 79))).         *)
(* Phase 10 wraps it with:                                                   *)
(*   ENTRY (pc+0x20 -> pc+0x6b): the canonical-state setup feeding INNER's    *)
(*     PRE (4 stack saves + 8 state loads + RDI:=b + lea K512(%rip),%rbp).    *)
(*   TAIL  (pc+0x1160 -> pc+0x11b8): the loop-exit deferred-sigma0 reconcile  *)
(*     (add %r14,%rax) + the 8-word feed-forward add-back into (%rdi).        *)
(* These segment lemmas + the K512 bytelist-explosion machinery + the spec-   *)
(* algebra (RECON/SB) are proved here; the composition follows in BLOCK.      *)
(* All PCs decoded fresh from objdump of the committed .o (NOT copied from     *)
(* SHA-256): ENTRY = orig 0x24..0x6f, TAIL = orig 0x1164..0x11bc.             *)
(* ------------------------------------------------------------------------- *)

(* Bytelist-explosion helpers (the SHA-256 file keeps these local too; the     *)
(* conversions they call - READ_MEMORY_BYTESIZED_SPLIT, WORD_ADD_ASSOC_CONSTS, *)
(* BYTELIST_EXPAND_CONV - live in base.ml's closure). *)
let INTRO_READ_MEMORY_FROM_BYTES8_TAC (t:term) =
  let r = REWRITE_CONV [READ_MEMORY_BYTESIZED_SPLIT] t in
  let r = REWRITE_RULE[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0;ARITH] r in
  MP_TAC r THEN
  ASM (GEN_REWRITE_TAC (LAND_CONV o ONCE_DEPTH_CONV)) [] THEN
  CONV_TAC (LAND_CONV WORD_REDUCE_CONV) THEN
  DISCH_TAC;;

let EXPLODE_BYTELIST_ASSUM_TAC const_data =
  FIRST_X_ASSUM (fun th ->
    let _ = find_term (fun t -> name_of t = "bytelist") (concl th) in
    let unfolded_bytes_loaded = REWRITE_RULE const_data th in
    MP_TAC (CONV_RULE (ONCE_DEPTH_CONV LENGTH_CONV THENC
                      LAND_CONV BYTELIST_EXPAND_CONV)
            unfolded_bytes_loaded)) THEN
  REWRITE_TAC [CONS_11] THEN
  STRIP_TAC;;

(* The 4 inner-loop sentinel bytes, read from the whole-rodata bytelist fact.  *)
(* 0x27/0x19/0xca continue (iterations 0,1,2); 0x00 terminates (iteration 3).  *)
(* [Δ256] 4 sentinels, not 3 (SHA-512 = 80 rounds = 16 head + 4*16 inner).     *)
let SHA512_SENTINEL_BYTES = prove
 (`!base:num s.
     read (memory :> bytelist (word base, LENGTH K512)) s = K512
     ==> read (memory :> bytes8 (word_add (word base) (word 519))) s = word 0x27 /\
         read (memory :> bytes8 (word_add (word base) (word 775))) s = word 0x19 /\
         read (memory :> bytes8 (word_add (word base) (word 1031))) s = word 0xca /\
         read (memory :> bytes8 (word_add (word base) (word 1287))) s = word 0x00`,
  REPEAT GEN_TAC THEN DISCH_TAC THEN
  EXPLODE_BYTELIST_ASSUM_TAC [K512_DATA] THEN
  REPEAT CONJ_TAC THEN ASM_REWRITE_TAC[]);;

(* The 80 round-constant reads as 8-byte bytes64 from the doubled K512 table.   *)
(* kofs t = 32*(t DIV 2) + 8*(t MOD 2)  (Phase-0 §2 offset formula).  Built     *)
(* programmatically (the 80-conjunct statement is generated, not typed).        *)
let SHA512_K512_READS =
  let kofs t = 32*(t/2) + 8*(t mod 2) in
  let one t =
    Printf.sprintf
      "read (memory :> bytes64 (word_add (word base) (word %d))) s = EL %d sha512_constants"
      (kofs t) t in
  let body = String.concat " /\\ " (map one (0--79)) in
  let goal = parse_term (Printf.sprintf
    "!base:num s:x86state. \
       read (memory :> bytelist (word base, LENGTH K512)) s = K512 \
       ==> %s" body) in
  prove
   (goal,
    REPEAT GEN_TAC THEN DISCH_TAC THEN
    EXPLODE_BYTELIST_ASSUM_TAC [K512_DATA] THEN
    REWRITE_TAC[sha512_constants] THEN
    CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN
    REWRITE_TAC[WORD_ADD_0] THEN
    REPEAT CONJ_TAC THEN
    (fun (asl,w) -> INTRO_READ_MEMORY_FROM_BYTES8_TAC (lhs w) (asl,w)) THEN
    ASM_REWRITE_TAC[]);;

(* ENTRY: tmc pc+0x20 (orig 0x24, just after `and $-64,%rsp`) -> pc+0x6b.       *)
(* 15 instructions: 4 stack saves (statep/dataptr/endp/origsp into 128..152     *)
(* (%rsp)), the 8 state loads `mov N(%rdi),reg`, the `jmp`, `mov %rbx,%rdi`     *)
(* (RDI := b for round 0's Maj seed) and `lea K512(%rip),%rbp`.  The rip-       *)
(* relative LEA result (word(val(word(pc+0x6b)) + val(word_sx(iword(&kk -       *)
(* (&pc+0x6b)))))) folds to `word kk` (= INNER's kbase) via RIP_REL_ADDR_FOLD;  *)
(* its riprel32_within_bounds side-condition rides as a precondition.  int64    *)
(* state (no word_zx).  Saved-slot offsets +128/136/144/152 [Δ256: +64..88].    *)
let SHA512_BLOCK_NOHW_ENTRY = prove
 (`!pc kk stackptr statep dataptr endp origsp a b c d e f g h.
     nonoverlapping (word pc,4578) (statep:int64,64) /\
     nonoverlapping (word pc,4578) (stackptr:int64,160) /\
     nonoverlapping (statep:int64,64) (stackptr:int64,160) /\
     riprel32_within_bounds kk (pc + 0x6b)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
            read RIP s = word (pc + 0x20) /\
            read RSP s = stackptr /\ read RDI s = statep /\ read RSI s = dataptr /\
            read RDX s = endp /\ read RAX s = origsp /\
            read (memory :> bytes64 statep) s = (a:int64) /\
            read (memory :> bytes64 (word_add statep (word 8))) s = (b:int64) /\
            read (memory :> bytes64 (word_add statep (word 16))) s = (c:int64) /\
            read (memory :> bytes64 (word_add statep (word 24))) s = (d:int64) /\
            read (memory :> bytes64 (word_add statep (word 32))) s = (e:int64) /\
            read (memory :> bytes64 (word_add statep (word 40))) s = (f:int64) /\
            read (memory :> bytes64 (word_add statep (word 48))) s = (g:int64) /\
            read (memory :> bytes64 (word_add statep (word 56))) s = (h:int64))
       (\s. read RIP s = word (pc + 0x6b) /\
            read RBP s = word kk /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RDI s = (b:int64) /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 136))) s = dataptr /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp /\
            read (memory :> bytes64 (word_add stackptr (word 152))) s = origsp)
       (MAYCHANGE [RIP;RDI;RBP;RAX;RBX;RCX;RDX;R8;R9;R10;R11;R12;R13;R14;R15] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 128));
                   memory :> bytes64 (word_add stackptr (word 136));
                   memory :> bytes64 (word_add stackptr (word 144));
                   memory :> bytes64 (word_add stackptr (word 152))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--15) THEN
  UNDISCH_TAC
   `read RBP s15 =
      word (val (word (pc + 107):(64)word) +
            val (word_sx (iword (&kk - (&pc + &107)):int32):(64)word):num)` THEN
  IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* Spec-algebra for the TAIL/BLOCK seam:                                       *)
(*   RECON : word_add (word_sub x s) s = x  (INNER's SPLIT RAX <-> TAIL's var0) *)
(*   SB    : the feed-forward add-back IS sha512_block, straight from the def.  *)
let RECON = prove
 (`!x s:int64. word_add (word_sub x s) s = x`, CONV_TAC WORD_RULE);;

let SB = prove
 (`!m a b c d e f g h.
     EL 0 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 0 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) a /\
     EL 1 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 1 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) b /\
     EL 2 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 2 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) c /\
     EL 3 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 3 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) d /\
     EL 4 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 4 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) e /\
     EL 5 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 5 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) f /\
     EL 6 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 6 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) g /\
     EL 7 (sha512_block m [a;b;c;d;e;f;g;h]) =
       word_add (EL 7 (sha512_compress_rounds m [a;b;c;d;e;f;g;h] 80)) h`,
  REWRITE_TAC[sha512_block] THEN
  CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;

(* TAIL: tmc pc+0x1160 (orig 0x1164, the loop-exit `mov 0x80(%rsp),%rdi`) ->    *)
(* pc+0x11b8 (orig 0x11bc, the outer `jb`, NOT executed).  20 instructions:     *)
(*   mov 0x80(%rsp),%rdi  (reload statep)                                       *)
(*   add %r14,%rax        (reconcile the deferred sigma0: va := va + r14_in)     *)
(*   lea 0x80(%rsi),%rsi  (advance dataptr; outer-loop bookkeeping)             *)
(*   add (%rdi),%rax ... add 0x38(%rdi),%r11  (8-word feed-forward add)         *)
(*   cmp 0x90(%rsp),%rsi  (outer-loop test, sets flags only)                    *)
(*   mov %rax,(%rdi) ... mov %r11,0x38(%rdi)  (store the 8 words back)          *)
(* Inputs RAX..R11 = working vars va..vh, R14 = r14_in; input state at          *)
(* (statep)+8i = s0v..s7v.  POST: statep+8i holds word_add (var i) s_i, with    *)
(* var 0 = word_add va r14_in.  int64 (no word_zx).                             *)
let SHA512_BLOCK_NOHW_TAIL = prove
 (`!pc kk stackptr statep dataptr va vb vc vd ve vf vg vh r14_in
    s0v s1v s2v s3v s4v s5v s6v s7v.
     nonoverlapping (word pc,4578) (statep:int64,64)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
            read RIP s = word (pc + 0x1160) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = (va:int64) /\
            read RBX s = (vb:int64) /\
            read RCX s = (vc:int64) /\
            read RDX s = (vd:int64) /\
            read R8 s  = (ve:int64) /\
            read R9 s  = (vf:int64) /\
            read R10 s = (vg:int64) /\
            read R11 s = (vh:int64) /\
            read R14 s = (r14_in:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 statep) s = (s0v:int64) /\
            read (memory :> bytes64 (word_add statep (word 8))) s = (s1v:int64) /\
            read (memory :> bytes64 (word_add statep (word 16))) s = (s2v:int64) /\
            read (memory :> bytes64 (word_add statep (word 24))) s = (s3v:int64) /\
            read (memory :> bytes64 (word_add statep (word 32))) s = (s4v:int64) /\
            read (memory :> bytes64 (word_add statep (word 40))) s = (s5v:int64) /\
            read (memory :> bytes64 (word_add statep (word 48))) s = (s6v:int64) /\
            read (memory :> bytes64 (word_add statep (word 56))) s = (s7v:int64))
       (\s. read RIP s = word (pc + 0x11b8) /\
            read (memory :> bytes64 statep) s =
                word_add (word_add va r14_in) s0v /\
            read (memory :> bytes64 (word_add statep (word 8))) s =
                word_add vb s1v /\
            read (memory :> bytes64 (word_add statep (word 16))) s =
                word_add vc s2v /\
            read (memory :> bytes64 (word_add statep (word 24))) s =
                word_add vd s3v /\
            read (memory :> bytes64 (word_add statep (word 32))) s =
                word_add ve s4v /\
            read (memory :> bytes64 (word_add statep (word 40))) s =
                word_add vf s5v /\
            read (memory :> bytes64 (word_add statep (word 48))) s =
                word_add vg s6v /\
            read (memory :> bytes64 (word_add statep (word 56))) s =
                word_add vh s7v)
       (MAYCHANGE [RIP;RDI;RSI;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes64 statep;
                   memory :> bytes64 (word_add statep (word 8));
                   memory :> bytes64 (word_add statep (word 16));
                   memory :> bytes64 (word_add statep (word 24));
                   memory :> bytes64 (word_add statep (word 32));
                   memory :> bytes64 (word_add statep (word 40));
                   memory :> bytes64 (word_add statep (word 48));
                   memory :> bytes64 (word_add statep (word 56))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--20) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ========================================================================= *)
(* SHA512_BLOCK_NOHW_BLOCK : ENTRY ; INNER ; TAIL = sha512_block.            *)
(*                                                                           *)
(* The full single-block correctness lemma.  Composes the three committed     *)
(* segment lemmas at the two clean seams (pc+0x6b ENTRY->INNER, pc+0x1160      *)
(* INNER->TAIL) via nested ENSURES_SEQUENCE_TAC.  Built PROGRAMMATICALLY by    *)
(* term surgery on the committed sub-lemmas (faithful int64 clone of the       *)
(* SHA-256 SHA256_BLOCK_NOHW_BLOCK builder; deltas: bytes64 / 8*i offsets /    *)
(* slot128 / no word_zx / cr80 / K512(1312) / tmc 4578).  PRE: entry state +   *)
(* 16 dataptr message reads + whole-K512 bytelist.  POST: statep+8i holds      *)
(* EL i (sha512_block m [a;..;h]) (the FIPS feed-forward result).              *)
(*                                                                           *)
(*   - ENTRY leg explodes the whole-K512 bytelist into the 80 K-reads +        *)
(*     4 sentinels (SHA512_K512_READS / SHA512_SENTINEL_BYTES) inside the      *)
(*     seam branch (the bytelist does NOT frame-carry; KDERIVE_ASSUME).        *)
(*   - INNER leg carries the 8 statep reads + slot128 to feed TAIL.            *)
(*   - TAIL leg reconciles the SPLIT exit (RECON: word_add(word_sub X s)s=X)   *)
(*     and rewrites the feed-forward add-back to sha512_block (SB).            *)
(* The hyp-free cold-gate PASS IS the seam-soundness evidence (a mismatched    *)
(* seam makes ENSURES_SEQUENCE_TAC / prove FAIL, never pass silently).         *)
(* ------------------------------------------------------------------------- *)
let SHA512_BLOCK_NOHW_BLOCK =
  (* ---- specialise the three committed segment lemmas for the chain ---- *)
  let INNER_i = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
     `dataptr:int64`;`a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;
     `g:int64`;`h:int64`;`m:int64 list`] SHA512_BLOCK_NOHW_INNER in
  let (_,ihyps,iPlam,iQlam,iC) = parts INNER_i in
  let sI,iPc = conjs_of_lam iPlam in
  let _,iQc = conjs_of_lam iQlam in
  let bighyp_i = hd ihyps in
  (* int64: read the raw post value (no word_zx strip). *)
  let raw_arg comp = rhs_of(by_comp comp iQc) in
  let TAIL_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
     `dataptr:int64`; raw_arg "RAX"; raw_arg "RBX"; raw_arg "RCX"; raw_arg "RDX";
     raw_arg "R8"; raw_arg "R9"; raw_arg "R10"; raw_arg "R11"; raw_arg "R14";
     `a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;`g:int64`;`h:int64`]
     SHA512_BLOCK_NOHW_TAIL in
  let (_,_,tPlam,tQlam,tC) = parts TAIL_i in
  let sT,tPc = conjs_of_lam tPlam in
  let _,tQc = conjs_of_lam tQlam in
  let ENTRY_i2 = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
     `dataptr:int64`;`endp:int64`;`origsp:int64`;`a:int64`;`b:int64`;`c:int64`;
     `d:int64`;`e:int64`;`f:int64`;`g:int64`;`h:int64`] SHA512_BLOCK_NOHW_ENTRY in
  let (_,_,ePlam,eQlam,eC) = parts ENTRY_i2 in
  let _,eQc = conjs_of_lam eQlam in
  let sE = fst(dest_abs eQlam) in
  let _,ePc = conjs_of_lam ePlam in
  let sEp = fst(dest_abs ePlam) in
  (* ---- address-flatten conv (nested word_add of constants -> one word) ---- *)
  let norm_conv = REWRITE_CONV[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0] THENC
                  DEPTH_CONV NUM_ADD_CONV in
  let normt t = try rhs(concl(norm_conv t)) with _ -> t in
  let norm_rule d = CONV_RULE norm_conv d in
  (* ---- Q at pc+0x6b (ENTRY->INNER seam) = INNER's full PRE (flattened, minus  *)
  (* bytes_loaded/RIP) INCLUDING the 80 K-reads + 4 sentinels, plus the 8 statep  *)
  (* reads + slot128 (ride INNER's frame to feed TAIL). ---- *)
  let drop_q c = is_named "bytes_loaded" c || comp_str c = "RIP" in
  let q_inner = map normt (filter (fun c -> not(drop_q c)) iPc) in
  let is_mem c = let cs=comp_str c in String.length cs>=6 && String.sub cs 0 6="memory" in
  let statep_reads = map (vsubst[sI,sEp]) (filter is_mem ePc) in
  let slot128 = vsubst[sI,sE]
     (by_comp "memory :> bytes64 (word_add stackptr (word 128))" eQc) in
  let blockQ6b = mk_abs(sI, list_mk_conj (q_inner @ statep_reads @ [slot128])) in
  (* ---- Q at pc+0x1160 (INNER->TAIL seam) = TAIL_i's PRE minus bytes_loaded/RIP ---- *)
  let q1160conjs =
    filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c<>"RIP") tPc in
  let blockQ1160 = mk_abs(sT, list_mk_conj q1160conjs) in
  (* ---- the full BLOCK statement (clean precondition set) ---- *)
  let block_pres =
   [ `nonoverlapping (word pc,4578) (statep:int64,64)`;
     `nonoverlapping (word pc,4578) (stackptr:int64,160)`;
     `nonoverlapping (word pc,4578) (dataptr:int64,128)`;
     `nonoverlapping (word pc,4578) (word kk:int64,1312)`;
     `nonoverlapping (statep:int64,64) (stackptr:int64,160)`;
     `nonoverlapping (statep:int64,64) (dataptr:int64,128)`;
     `nonoverlapping (statep:int64,64) (word kk:int64,1312)`;
     `nonoverlapping (stackptr:int64,160) (dataptr:int64,128)`;
     `nonoverlapping (stackptr:int64,160) (word kk:int64,1312)`;
     `riprel32_within_bounds kk (pc + 0x6b)` ] in
  let sv = `s:x86state` in
  let entry_pre = map (vsubst[sv,sEp]) ePc in
  let dataptr_reads = map (vsubst[sv,sI])
    (filter (fun c -> is_mem c &&
        (try let _=find_term (fun t->is_const t &&
                fst(dest_const t)="word_bytereverse") c in true with _->false)) iPc) in
  let blk_bytelist =
     `read (memory :> bytelist (word kk:int64, LENGTH K512)) (s:x86state) = K512` in
  let blockPRE = mk_abs(sv, list_mk_conj (entry_pre @ dataptr_reads @ [blk_bytelist])) in
  let el_blk i = vsubst[mk_small_numeral i,`i:num`]
     `EL i (sha512_block m [a;b;c;d;e;f;g;h]):int64` in
  let post_read i = vsubst[sv,sT]
     (fst(dest_eq(by_comp (if i=0 then "memory :> bytes64 statep"
          else "memory :> bytes64 (word_add statep (word "^string_of_int(8*i)^"))")
          tQc))) in
  let block_post_conjs =
    `read RIP s = word (pc + 0x11b8)` ::
    (map (fun i -> mk_eq(post_read i, el_blk i)) (0--7)) in
  let blockPOST = mk_abs(sv, list_mk_conj block_post_conjs) in
  let blockFRAME = mk_comb(mk_comb(seqop, mk_comb(mk_comb(seqop,eC),iC)),tC) in
  let eh = ens_head_of INNER_i in
  let block_concl =
    list_mk_forall([`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
                    `dataptr:int64`;`endp:int64`;`origsp:int64`;
                    `a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;
                    `g:int64`;`h:int64`;`m:int64 list`],
      itlist (curry mk_imp) block_pres
        (mk_ensures eh blockPRE blockPOST blockFRAME)) in
  (* ---- leg tactics ---- *)
  let match_leg lemma =
    W(fun (asl,w) -> ignore asl;
        let kv = goal_rodata_var w in
        MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kdat:num`] lemma)) THEN
        ASM_REWRITE_TAC[]) in
  let sublem_a = ENSURES_SUBLEMMA_TAC execup in
  let INNER_HYP_CLOSER =
    REWRITE_TAC[NONOVERLAPPING_CLAUSES] THEN REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE CONV_TAC WORD_REDUCE_CONV ORELSE CONV_TAC WORD_RULE) in
  let INNER_SEAM_RECON =
    REWRITE_TAC[WORD_ADD_ASSOC_CONSTS; WORD_ADD_0] THEN
    CONV_TAC(DEPTH_CONV NUM_ADD_CONV) THEN ASM_REWRITE_TAC[] in
  let inner_leg =
    SUBGOAL_THEN bighyp_i ASSUME_TAC THENL
     [ INNER_HYP_CLOSER;
       match_leg INNER_i THEN sublem_a "s" "s'" THEN INNER_SEAM_RECON ] in
  let tail_leg =
    match_leg TAIL_i THEN
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC;
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
      W(fun (asl,w) -> ignore asl;
        X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
      REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
      REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
      REWRITE_TAC[GSYM SEQ_ASSOC] THEN
      PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
      CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
      REWRITE_TAC[ASSIGNS_THM] THEN
      REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
      NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
      ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
      REWRITE_TAC[SB] THEN RULE_ASSUM_TAC(REWRITE_RULE[RECON]) THEN
      ASM_REWRITE_TAC[]] in
  let KDERIVE_ASSUME =
    FIRST_ASSUM(fun th ->
          let c = concl th in
          if is_eq c && (try fst(dest_const(rand c))="K512" with _->false)
          then ASSUME_TAC(norm_rule(MATCH_MP SHA512_K512_READS th)) THEN
               ASSUME_TAC(norm_rule(MATCH_MP SHA512_SENTINEL_BYTES th))
          else NO_TAC) in
  let entry_leg =
    match_leg ENTRY_i2 THEN
    MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
     [ W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
       STRIP_TAC THEN ASM_REWRITE_TAC[];
       CONJ_TAC THENL [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC; ALL_TAC] THEN
       W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
       W(fun (asl,w) -> ignore asl;
         X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
       REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
       KDERIVE_ASSUME THEN
       REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
       REWRITE_TAC[GSYM SEQ_ASSOC] THEN
       PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
       CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
       REWRITE_TAC[ASSIGNS_THM] THEN
       REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
       NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
       ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
       ASM_REWRITE_TAC[] ] in
  prove
   (block_concl,
    REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT STRIP_TAC THEN
    ENSURES_SEQUENCE_TAC `pc + 0x6b` blockQ6b THEN CONJ_TAC THENL
     [ entry_leg;
       ENSURES_SEQUENCE_TAC `pc + 0x1160` blockQ1160 THEN CONJ_TAC THENL
        [ inner_leg; tail_leg ] ]);;

(* ========================================================================= *)
(* Phase 11 - outer multi-block loop -> SHA512_COMPRESS_CORRECT.              *)
(*                                                                           *)
(* The outer do-while wraps the single-block body (MINI ; INNER ; TAIL_LP)    *)
(* via ENSURES_WHILE_PUP, prefixed by the register-prologue PROL_REG (once).  *)
(* int64 1:1 clone of SHA256_COMPRESS_CORRECT (~L6747-7530 of the SHA-256     *)
(* file). PCs decoded fresh from objdump (tmc = orig-4):                      *)
(*   loop-top   = pc+0x61   (orig 0x65, `mov %rbx,%rdi`)                       *)
(*   MINI->INNER seam = pc+0x6b (orig 0x6f)                                   *)
(*   INNER->TAIL_LP seam = pc+0x1160 (orig 0x1164)                            *)
(*   back-edge `jb` = pc+0x11b8 (orig 0x11bc, jb is 6 bytes)                  *)
(*   loop exit = pc+0x11be (orig 0x11c2)                                      *)
(*   end-test `cmp 0x90(%rsp),%rsi` reads slot144=endp (orig 0x1195)          *)
(* Decompose: PROL_REG (pc+0x20->pc+0x61, ONCE) ; loop over BODY where         *)
(*   BODY = MINI (pc+0x61->pc+0x6b) ; INNER (pc+0x6b->pc+0x1160) ;             *)
(*          TAIL_LP (pc+0x1160->pc+0x11b8, w/ CF).                            *)
(* [Δ256] int64/bytes64 / 8*i state offsets / 128*i blocks / slots 128/136/   *)
(*   144/152 / K512=1312 / tmc=4578 / 80 rounds / endp=data+128*num_blocks.   *)
(* ------------------------------------------------------------------------- *)

(* PROL_REG: pc+0x20 -> pc+0x61, the one-time prologue.  13 instrs: 4 stack    *)
(* saves (statep/dataptr/endp/origsp -> 128+N(%rsp)) + 8 state loads -> regs.  *)
let SHA512_BLOCK_NOHW_PROL_REG = prove
 (`!pc kk stackptr statep dataptr endp origsp a b c d e f g h.
     nonoverlapping (word pc,4578) (statep:int64,64) /\
     nonoverlapping (word pc,4578) (stackptr:int64,160) /\
     nonoverlapping (statep:int64,64) (stackptr:int64,160)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
            read RIP s = word (pc + 0x20) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = dataptr /\
            read RDX s = endp /\
            read RAX s = origsp /\
            read (memory :> bytes64 statep) s = (a:int64) /\
            read (memory :> bytes64 (word_add statep (word 8))) s = (b:int64) /\
            read (memory :> bytes64 (word_add statep (word 16))) s = (c:int64) /\
            read (memory :> bytes64 (word_add statep (word 24))) s = (d:int64) /\
            read (memory :> bytes64 (word_add statep (word 32))) s = (e:int64) /\
            read (memory :> bytes64 (word_add statep (word 40))) s = (f:int64) /\
            read (memory :> bytes64 (word_add statep (word 48))) s = (g:int64) /\
            read (memory :> bytes64 (word_add statep (word 56))) s = (h:int64))
       (\s. read RIP s = word (pc + 0x61) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 136))) s = dataptr /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp /\
            read (memory :> bytes64 (word_add stackptr (word 152))) s = origsp)
       (MAYCHANGE [RIP;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes64 (word_add stackptr (word 128));
                   memory :> bytes64 (word_add stackptr (word 136));
                   memory :> bytes64 (word_add stackptr (word 144));
                   memory :> bytes64 (word_add stackptr (word 152))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--13) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN
  TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* MINI: pc+0x61 -> pc+0x6b, the 2 loop-top instrs: mov %rbx,%rdi ;            *)
(* lea K512(%rip),%rbp.  PRE/POST pin the full register/slot state INNER       *)
(* consumes (ride the tiny [RIP;RDI;RBP] frame unchanged).                     *)
let SHA512_BLOCK_NOHW_MINI = prove
 (`!pc kk stackptr dataptr statep endp a b c d e f g h.
     riprel32_within_bounds kk (pc + 0x6b)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
            read RIP s = word (pc + 0x61) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp)
       (\s. read RIP s = word (pc + 0x6b) /\
            read RBP s = word kk /\
            read RDI s = (b:int64) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = (a:int64) /\
            read RBX s = (b:int64) /\
            read RCX s = (c:int64) /\
            read RDX s = (d:int64) /\
            read R8 s  = (e:int64) /\
            read R9 s  = (f:int64) /\
            read R10 s = (g:int64) /\
            read R11 s = (h:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp)
       (MAYCHANGE [RIP;RDI;RBP] ,, MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--2) THEN
  UNDISCH_TAC
   `read RBP s2 =
      word (val (word (pc + 107):(64)word) +
            val (word_sx (iword (&kk - (&pc + &107)):int32):(64)word):num)` THEN
  IMP_REWRITE_TAC[RIP_REL_ADDR_FOLD] THEN ASM_REWRITE_TAC[] THEN DISCH_TAC THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN TRY REFL_TAC THEN
  TRY (AP_TERM_TAC THEN CONV_TAC WORD_RULE));;

(* TAIL_LP: pc+0x1160 -> pc+0x11b8 (orig 0x11bc `jb`, NOT executed).  20       *)
(* instrs (same as committed TAIL) but POST keeps the register state +         *)
(* RSI advance (+128) + CF + RDI=statep that the outer back-edge `jb` needs.   *)
(* CF fact: read CF s <=> val (dataptr+128) < val endp (the back-edge cond).   *)
(* New working state lands in regs AND memory[statep+8i].  nonoverlapping      *)
(* (statep,64)(stackptr,160) so the feed-forward stores don't clobber          *)
(* slot128/slot144 (statep/endp).                                             *)
let SHA512_BLOCK_NOHW_TAIL_LP = prove
 (`!pc kk stackptr statep dataptr endp va vb vc vd ve vf vg vh r14_in
    s0v s1v s2v s3v s4v s5v s6v s7v.
     nonoverlapping (word pc,4578) (statep:int64,64) /\
     nonoverlapping (statep:int64,64) (stackptr:int64,160)
     ==> ensures x86
       (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
            read RIP s = word (pc + 0x1160) /\
            read RSP s = stackptr /\
            read RSI s = dataptr /\
            read RAX s = (va:int64) /\
            read RBX s = (vb:int64) /\
            read RCX s = (vc:int64) /\
            read RDX s = (vd:int64) /\
            read R8 s  = (ve:int64) /\
            read R9 s  = (vf:int64) /\
            read R10 s = (vg:int64) /\
            read R11 s = (vh:int64) /\
            read R14 s = (r14_in:int64) /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp /\
            read (memory :> bytes64 statep) s = (s0v:int64) /\
            read (memory :> bytes64 (word_add statep (word 8))) s = (s1v:int64) /\
            read (memory :> bytes64 (word_add statep (word 16))) s = (s2v:int64) /\
            read (memory :> bytes64 (word_add statep (word 24))) s = (s3v:int64) /\
            read (memory :> bytes64 (word_add statep (word 32))) s = (s4v:int64) /\
            read (memory :> bytes64 (word_add statep (word 40))) s = (s5v:int64) /\
            read (memory :> bytes64 (word_add statep (word 48))) s = (s6v:int64) /\
            read (memory :> bytes64 (word_add statep (word 56))) s = (s7v:int64))
       (\s. read RIP s = word (pc + 0x11b8) /\
            read RSP s = stackptr /\
            read RDI s = statep /\
            read RSI s = word_add dataptr (word 128) /\
            (read CF s <=> val (word_add dataptr (word 128)) < val endp) /\
            read RAX s = word_add (word_add va r14_in) s0v /\
            read RBX s = word_add vb s1v /\
            read RCX s = word_add vc s2v /\
            read RDX s = word_add vd s3v /\
            read R8 s  = word_add ve s4v /\
            read R9 s  = word_add vf s5v /\
            read R10 s = word_add vg s6v /\
            read R11 s = word_add vh s7v /\
            read (memory :> bytes64 (word_add stackptr (word 128))) s = statep /\
            read (memory :> bytes64 (word_add stackptr (word 144))) s = endp /\
            read (memory :> bytes64 statep) s =
                word_add (word_add va r14_in) s0v /\
            read (memory :> bytes64 (word_add statep (word 8))) s =
                word_add vb s1v /\
            read (memory :> bytes64 (word_add statep (word 16))) s =
                word_add vc s2v /\
            read (memory :> bytes64 (word_add statep (word 24))) s =
                word_add vd s3v /\
            read (memory :> bytes64 (word_add statep (word 32))) s =
                word_add ve s4v /\
            read (memory :> bytes64 (word_add statep (word 40))) s =
                word_add vf s5v /\
            read (memory :> bytes64 (word_add statep (word 48))) s =
                word_add vg s6v /\
            read (memory :> bytes64 (word_add statep (word 56))) s =
                word_add vh s7v)
       (MAYCHANGE [RIP;RDI;RSI;RAX;RBX;RCX;RDX;R8;R9;R10;R11] ,,
        MAYCHANGE [memory :> bytes64 statep;
                   memory :> bytes64 (word_add statep (word 8));
                   memory :> bytes64 (word_add statep (word 16));
                   memory :> bytes64 (word_add statep (word 24));
                   memory :> bytes64 (word_add statep (word 32));
                   memory :> bytes64 (word_add statep (word 40));
                   memory :> bytes64 (word_add statep (word 48));
                   memory :> bytes64 (word_add statep (word 56))] ,,
        MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`,
  REWRITE_TAC[SOME_FLAGS; NONOVERLAPPING_CLAUSES] THEN REPEAT STRIP_TAC THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--20) THEN
  ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[] THEN
  REPEAT CONJ_TAC THEN
  TRY(ASM_REWRITE_TAC[] THEN NO_TAC) THEN
  TRY AP_TERM_TAC THEN CONV_TAC WORD_RULE);;

(* ========================================================================= *)
(* Core CORRECT.  Built PROGRAMMATICALLY (int64 clone of the SHA-256 builder). *)
(* ========================================================================= *)

(* ---- local term/util helpers (self-contained; shadow toplevel harmlessly) - *)
let norm_conv = REWRITE_CONV[WORD_ADD_ASSOC_CONSTS;WORD_ADD_0] THENC
                DEPTH_CONV NUM_ADD_CONV;;
let normt t = try rhs(concl(norm_conv t)) with _ -> t;;
let is_mem c = let cs=comp_str c in String.length cs>=6 && String.sub cs 0 6="memory";;
let is_kread c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="sha512_constants") c
        in true with _->false);;
let is_sentinel c = is_mem c &&
   (try let _=find_term (fun t->is_const t && fst(dest_const t)="bytes8") c
        in true with _->false);;
let at_state sv c = vsubst[sv, `s:x86state`] c;;
let stnames = ["a";"b";"c";"d";"e";"f";"g";"h"];;
let regnames = ["RAX";"RBX";"RCX";"RDX";"R8";"R9";"R10";"R11"];;

(* INNER's PRE conjuncts, kbase:=word kk, flattened - source of K-reads/sentinels.*)
let INNER_i0 = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   `dataptr:int64`;`a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;
   `g:int64`;`h:int64`;`m:int64 list`] SHA512_BLOCK_NOHW_INNER;;
let (_,_,iPlam0,_,_) = parts INNER_i0;;
let _,iPc0 = conjs_of_lam iPlam0;;
let kread_terms = map normt (filter is_kread iPc0);;
let sentinel_terms = map normt (filter is_sentinel iPc0);;

let el_hb j ivar =
  vsubst[ivar,`i:num`; mk_small_numeral j,`j:num`]
    `EL j (sha512_hash_blocks (m_fn:num->int64 list) [a;b;c;d;e;f;g;h] i):int64`;;

(* p i s : loop invariant STATE predicate (NO bytes_loaded/RIP - auto-injected). *)
let p_conjs ivar sv =
  let regeq j = mk_eq(parse_term("read "^(el j regnames)^" sQQ"), el_hb j ivar) in
  let regeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (regeq j)) (0--7) in
  let mem_state j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(8*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes64 "^addr^") sQQ"), el_hb j ivar) in
  let memeqs = map (fun j -> vsubst[sv,`sQQ:x86state`] (mem_state j)) (0--7) in
  let rsp  = vsubst[sv,`sQQ:x86state`] (parse_term "read RSP sQQ = stackptr") in
  let rdi  = vsubst[sv,`sQQ:x86state`] (parse_term "read RDI sQQ = statep") in
  let rsi  = vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
               (parse_term "read RSI sQQ = word_add dataptr (word (128*i))") in
  let slot128 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 128))) sQQ = statep") in
  let slot144 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 144))) sQQ = endp") in
  let slot152 = vsubst[sv,`sQQ:x86state`]
       (parse_term "read (memory :> bytes64 (word_add stackptr (word 152))) sQQ = origsp") in
  let dataq = vsubst[sv,`sQQ:x86state`]
       (parse_term
         ("!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes64 \
             (word_add dataptr (word (128*i' + 8*j)))) sQQ = \
           word_bytereverse (EL j (m_fn i'):int64)")) in
  let kr = map (at_state sv) kread_terms in
  let sn = map (at_state sv) sentinel_terms in
  [rsp; rdi; rsi; slot128; slot144; slot152] @ regeqs @ memeqs @ kr @ sn @ [dataq];;

let q_conj ivar sv =
  vsubst[sv,`sQQ:x86state`; ivar,`i:num`]
    (parse_term
      "(read CF sQQ <=> val (word_add (dataptr:int64) (word (128*i))) < val (endp:int64))");;

let iv_var = `i:num` and sx = `s:x86state`;;
let invariant =
  list_mk_abs([iv_var; sx],
    mk_conj(list_mk_conj (p_conjs iv_var sx), q_conj iv_var sx));;

(* ---- CORRECT statement ---- *)
let correct_pres =
 [ `nonoverlapping (word pc,4578) (statep:int64,64)`;
   `nonoverlapping (word pc,4578) (stackptr:int64,160)`;
   `nonoverlapping (word pc,4578) (dataptr:int64,128*num_blocks)`;
   `nonoverlapping (word pc,4578) (word kk:int64,1312)`;
   `nonoverlapping (statep:int64,64) (stackptr:int64,160)`;
   `nonoverlapping (statep:int64,64) (dataptr:int64,128*num_blocks)`;
   `nonoverlapping (statep:int64,64) (word kk:int64,1312)`;
   `nonoverlapping (stackptr:int64,160) (dataptr:int64,128*num_blocks)`;
   `nonoverlapping (stackptr:int64,160) (word kk:int64,1312)`;
   `0 < num_blocks`;
   `val (dataptr:int64) + 128 * num_blocks < 2 EXP 64`;
   `endp:int64 = word_add dataptr (word (128*num_blocks))`;
   `riprel32_within_bounds kk (pc + 0x6b)` ];;

let correct_PRE =
  let statep_read j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(8*j)^"))" in
    parse_term("read (memory :> bytes64 "^addr^") s = ("^el j stnames^":int64)") in
  let conjs =
    [ `bytes_loaded s (word pc) (sha512_compress_tmc pc kk)`;
      `read RIP s = word (pc + 0x20)`;
      `read RSP s = stackptr`;
      `read RDI s = statep`;
      `read RSI s = dataptr`;
      `read RDX s = endp`;
      `read RAX s = origsp` ]
    @ (map statep_read (0--7))
    @ [ `read (memory :> bytelist (word kk:int64, LENGTH K512)) s = K512` ;
        parse_term
         "!i' j. i' < num_blocks /\\ j < 16 ==> \
           read (memory :> bytes64 \
             (word_add dataptr (word (128*i' + 8*j)))) s = \
           word_bytereverse (EL j (m_fn i'):int64)" ] in
  mk_abs(`s:x86state`, list_mk_conj conjs);;

let correct_POST =
  let stp j =
    let addr = if j=0 then "statep"
               else "(word_add statep (word "^string_of_int(8*j)^"))" in
    mk_eq(parse_term("read (memory :> bytes64 "^addr^") s"),
          vsubst[mk_small_numeral j,`j:num`]
            `EL j (sha512_hash_blocks (m_fn:num->int64 list)
                     [a;b;c;d;e;f;g;h] num_blocks):int64`) in
  mk_abs(`s:x86state`,
    list_mk_conj([`read RIP s = word (pc + 0x11be)`;
                  `read RSP s = stackptr`;
                  `read (memory :> bytes64 (word_add stackptr (word 152))) s =
                       origsp`]
                 @ map stp (0--7)));;

(* frame: all 16 GP regs, 8 statep bytes64, 4 stack slots bytes64, 16 W-ring   *)
(* bytes64, flags, events. *)
let frame_full =
  `(MAYCHANGE [RIP;RAX;RBX;RCX;RDX;RBP;RDI;RSI;R8;R9;R10;R11;R12;R13;R14;R15] ,,
    MAYCHANGE [memory :> bytes64 statep;
               memory :> bytes64 (word_add statep (word 8));
               memory :> bytes64 (word_add statep (word 16));
               memory :> bytes64 (word_add statep (word 24));
               memory :> bytes64 (word_add statep (word 32));
               memory :> bytes64 (word_add statep (word 40));
               memory :> bytes64 (word_add statep (word 48));
               memory :> bytes64 (word_add statep (word 56))] ,,
    MAYCHANGE [memory :> bytes64 (word_add stackptr (word 128));
               memory :> bytes64 (word_add stackptr (word 136));
               memory :> bytes64 (word_add stackptr (word 144));
               memory :> bytes64 (word_add stackptr (word 152))] ,,
    MAYCHANGE [memory :> bytes64 stackptr;
               memory :> bytes64 (word_add stackptr (word 8));
               memory :> bytes64 (word_add stackptr (word 16));
               memory :> bytes64 (word_add stackptr (word 24));
               memory :> bytes64 (word_add stackptr (word 32));
               memory :> bytes64 (word_add stackptr (word 40));
               memory :> bytes64 (word_add stackptr (word 48));
               memory :> bytes64 (word_add stackptr (word 56));
               memory :> bytes64 (word_add stackptr (word 64));
               memory :> bytes64 (word_add stackptr (word 72));
               memory :> bytes64 (word_add stackptr (word 80));
               memory :> bytes64 (word_add stackptr (word 88));
               memory :> bytes64 (word_add stackptr (word 96));
               memory :> bytes64 (word_add stackptr (word 104));
               memory :> bytes64 (word_add stackptr (word 112));
               memory :> bytes64 (word_add stackptr (word 120))] ,,
    MAYCHANGE SOME_FLAGS ,, MAYCHANGE [events])`;;

let correct_concl =
  list_mk_forall([`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
                  `dataptr:int64`;`endp:int64`;`origsp:int64`;`num_blocks:num`;
                  `a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;
                  `g:int64`;`h:int64`;`m_fn:num->int64 list`],
    itlist (curry mk_imp) correct_pres
      (mk_ensures `ensures x86` correct_PRE correct_POST frame_full));;

let q_top = mk_abs(`s:x86state`, list_mk_conj (p_conjs `0` `s:x86state`));;

(* ============================ leg1 (PROL_REG once) ====================== *)
let PROL_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   `dataptr:int64`;`endp:int64`;`origsp:int64`;`a:int64`;`b:int64`;`c:int64`;
   `d:int64`;`e:int64`;`f:int64`;`g:int64`;`h:int64`] SHA512_BLOCK_NOHW_PROL_REG;;

let match_leg lemma =
  W(fun (asl,w) -> ignore asl;
      let kv = goal_rodata_var w in
      MP_TAC (REWRITE_RULE[SOME_FLAGS] (INST [kv, `kk:num`] lemma)) THEN
      ASM_REWRITE_TAC[]);;
let norm_rule d = CONV_RULE norm_conv d;;
let KDERIVE_ASSUME =
  FIRST_ASSUM(fun th ->
        let c = concl th in
        if is_eq c && (try fst(dest_const(rand c))="K512" with _->false)
        then ASSUME_TAC(norm_rule(MATCH_MP SHA512_K512_READS th)) THEN
             ASSUME_TAC(norm_rule(MATCH_MP SHA512_SENTINEL_BYTES th))
        else NO_TAC);;
let P0_RECON =
  REWRITE_TAC[sha512_hash_blocks] THEN
  CONV_TAC(DEPTH_CONV EL_CONV) THEN
  REWRITE_TAC[MULT_CLAUSES; WORD_ADD_0; ARITH] THEN
  CONV_TAC(DEPTH_CONV NUM_MULT_CONV) THEN REWRITE_TAC[WORD_ADD_0];;

let leg1 =
  match_leg PROL_i THEN
  MATCH_MP_TAC ENSURES_SUBLEMMA_THM THEN REWRITE_TAC[] THEN CONJ_TAC THENL
   [ W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     STRIP_TAC THEN ASM_REWRITE_TAC[];
     CONJ_TAC THENL [SUBSUMED_MAYCHANGE_TAC THEN NO_TAC; ALL_TAC] THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s",type_of(fst(dest_forall w))))) THEN
     W(fun (asl,w) -> ignore asl;
       X_GEN_TAC(mk_var("s'",type_of(fst(dest_forall w))))) THEN
     REPEAT(DISCH_THEN(CONJUNCTS_THEN2 STRIP_ASSUME_TAC MP_TAC)) THEN
     KDERIVE_ASSUME THEN
     REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
     REWRITE_TAC[GSYM SEQ_ASSOC] THEN
     PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
     CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
     REWRITE_TAC[ASSIGNS_THM] THEN
     REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
     NONSELFMODIFYING_STATE_UPDATE_TAC execup THEN
     ASSUMPTION_STATE_UPDATE_TAC THEN DISCH_THEN(K ALL_TAC) THEN
     P0_RECON THEN ASM_REWRITE_TAC[] ];;

(* ============================ CF legs (back-edge + exit) ================= *)
let CFLT = prove
 (`!(dataptr:int64) i num_blocks.
     i < num_blocks /\ val dataptr + 128 * num_blocks < 2 EXP 64
     ==> val (word_add dataptr (word (128*i))) <
         val (word_add dataptr (word (128*num_blocks)))`,
  REPEAT STRIP_TAC THEN
  REWRITE_TAC[VAL_WORD_ADD; VAL_WORD; DIMINDEX_64] THEN
  SUBGOAL_THEN `(128 * i) MOD 2 EXP 64 = 128 * i /\
                (128 * num_blocks) MOD 2 EXP 64 = 128 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ALL_TAC] THEN
  SUBGOAL_THEN `(val(dataptr:int64) + 128 * i) MOD 2 EXP 64 =
                 val dataptr + 128 * i /\
                (val(dataptr:int64) + 128 * num_blocks) MOD 2 EXP 64 =
                 val dataptr + 128 * num_blocks`
    (CONJUNCTS_THEN SUBST1_TAC) THENL
   [CONJ_TAC THEN MATCH_MP_TAC MOD_LT THEN ASM_ARITH_TAC; ASM_ARITH_TAC]);;

let endp_def = `endp:int64 = word_add dataptr (word (128 * num_blocks))`;;

let leg_back =
  REPEAT STRIP_TAC THEN
  SUBGOAL_THEN `val (word_add (dataptr:int64) (word (128*i))) <
                val (word_add dataptr (word (128*num_blocks)))`
    ASSUME_TAC THENL
   [ MATCH_MP_TAC CFLT THEN ASM_REWRITE_TAC[]; ALL_TAC ] THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN ASM_REWRITE_TAC[];;

let leg_exit =
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--1) THEN
  ENSURES_FINAL_STATE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME endp_def]) THEN
  ASM_REWRITE_TAC[LT_REFL];;

(* ============================ BODY_FF (inline body leg) ================== *)
let HB iv = vsubst[iv,`i:num`]
  `sha512_hash_blocks (m_fn:num->int64 list) [a;b;c;d;e;f;g;h] i`;;
let elhb iv j = mk_comb(mk_comb(`EL:num->int64 list->int64`, mk_small_numeral j), HB iv);;

let iv = `i:num` and ip1 = `i + 1` and sxv = `s:x86state`;;
let dptr_i = `word_add dataptr (word (128*i)):int64`;;

let INNER_i = SPECL [`pc:num`;`kk:num`;`word kk:int64`;`stackptr:int64`;
   dptr_i; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4; elhb iv 5;
   elhb iv 6; elhb iv 7; `(m_fn:num->int64 list) i`] SHA512_BLOCK_NOHW_INNER;;
let (_,ihyps,iPlam,iQlam,iC) = parts INNER_i;;
let sI,iPc = conjs_of_lam iPlam;;
let _,iQc = conjs_of_lam iQlam;;
let bighyp_i = hd ihyps;;
let raw_arg comp = rhs_of(by_comp comp iQc);;

let MINI_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`; dptr_i;
   `statep:int64`;`endp:int64`; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3;
   elhb iv 4; elhb iv 5; elhb iv 6; elhb iv 7] SHA512_BLOCK_NOHW_MINI;;
let (_,_,mPlam,mQlam,mC) = parts MINI_i;;
let sM,mPc = conjs_of_lam mPlam;;

let TAILLP_i = SPECL [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;
   dptr_i;`endp:int64`; raw_arg "RAX"; raw_arg "RBX"; raw_arg "RCX";
   raw_arg "RDX"; raw_arg "R8"; raw_arg "R9"; raw_arg "R10"; raw_arg "R11";
   raw_arg "R14"; elhb iv 0; elhb iv 1; elhb iv 2; elhb iv 3; elhb iv 4;
   elhb iv 5; elhb iv 6; elhb iv 7] SHA512_BLOCK_NOHW_TAIL_LP;;
let (_,_,tPlam,tQlam,tC) = parts TAILLP_i;;
let sT,tPc = conjs_of_lam tPlam;;
let _,tQc = conjs_of_lam tQlam;;

let pconj_i  = p_conjs iv  sxv;;
let pconj_ip1 = p_conjs ip1 sxv;;
(* read-only / frame-preserved facts riding every segment frame untouched:     *)
(* the 80 K-reads, 4 sentinels, the quantified dataq, AND slot152=origsp.       *)
let ro_i = filter (fun c -> is_kread c || is_sentinel c || not(is_eq c) ||
                            vfree_in `origsp:int64` c) pconj_i;;

let statep_read_i sv j =
  let addr = if j=0 then "statep" else "(word_add statep (word "^string_of_int(8*j)^"))" in
  mk_eq(parse_term("read (memory :> bytes64 "^addr^") sQQ"), elhb iv j)
  |> vsubst[sv,`sQQ:x86state`];;
let slot128v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 128))) sQQ = statep");;
let slot144v sv = vsubst[sv,`sQQ:x86state`]
   (parse_term "read (memory :> bytes64 (word_add stackptr (word 144))) sQQ = endp");;

let drop c = is_named "bytes_loaded" c || comp_str c = "RIP";;
let q6b_inner = map normt (filter (fun c -> not(drop c)) iPc);;
let q6b_extra = (map (statep_read_i sI) (0--7)) @ [slot128v sI; slot144v sI];;
let ro_at sv = map (vsubst[sv,sxv]) ro_i;;
let already c = exists (fun d -> aconv c d) (q6b_inner @ q6b_extra);;
let q6b_ro = filter (fun c -> not(already c)) (ro_at sI);;
let bodyQ6b = mk_abs(sI, list_mk_conj (q6b_inner @ q6b_extra @ q6b_ro));;

let q1160_tl = filter (fun c -> not(is_named "bytes_loaded" c) && comp_str c<>"RIP") tPc;;
let already2 c = exists (fun d -> aconv c d) q1160_tl;;
let q1160_ro = filter (fun c -> not(already2 c)) (ro_at sT);;
let bodyQ1160 = mk_abs(sT, list_mk_conj (q1160_tl @ q1160_ro));;

(* BODY_FF statement on frame_full with p(i+1) GROUPED. *)
let ff_PRE =
  mk_abs(sxv, list_mk_conj
    (`bytes_loaded s (word pc) (sha512_compress_tmc pc kk)` ::
     `read RIP s = word (pc + 0x61)` :: pconj_i));;
let ff_POST =
  mk_abs(sxv, list_mk_conj
    [`bytes_loaded s (word pc) (sha512_compress_tmc pc kk)`;
     `read RIP s = word (pc + 0x11b8)`;
     list_mk_conj pconj_ip1;
     q_conj ip1 sxv]);;
let ff_FRAME = frame_full;;
let ff_hyps = correct_pres @ [`i < num_blocks`; `~(i = num_blocks)`];;
let ff_vars =
  [`pc:num`;`kk:num`;`stackptr:int64`;`statep:int64`;`dataptr:int64`;
   `endp:int64`;`origsp:int64`;`num_blocks:num`;`i:num`;`a:int64`;`b:int64`;
   `c:int64`;`d:int64`;`e:int64`;`f:int64`;`g:int64`;`h:int64`;
   `m_fn:num->int64 list`];;
let eh = ens_head_of INNER_i;;
let ff_body0 = itlist (curry mk_imp) ff_hyps (mk_ensures eh ff_PRE ff_POST ff_FRAME);;
let stray_tyvars =
  itlist (fun v acc ->
     let n = fst(dest_var v) in
     if (n="i" || n="num_blocks") && type_of v <> `:num`
     then union (tyvars (type_of v)) acc else acc)
    (frees ff_body0) [];;
let ff_body = inst (map (fun tv -> (`:num`,tv)) stray_tyvars) ff_body0;;
let ff_concl = list_mk_forall(ff_vars, ff_body);;

(* ---- BODY_FF proof tactic ---- *)
let msg_reads_i =
  filter (fun c -> is_mem c &&
     (try let _=find_term (fun t->is_const t &&
             fst(dest_const t)="word_bytereverse") c in true with _->false))
    iPc;;
let msg_template = map normt msg_reads_i;;
let aug_of_prelam plam =
  let sv,body = dest_abs plam in
  let rsi = find (fun c -> try comp_str c = "RSI" with _ -> false) (conjuncts body) in
  let gi = rand(rand(rand(rhs_of rsi))) in
  let msgs = map (fun c -> vsubst[sv,sI; gi,`i:num`] c) msg_template in
  mk_abs(sv, list_mk_conj (conjuncts body @ msgs));;

let sublem_a = ENSURES_SUBLEMMA_TAC execup;;
let INNER_HYP_CLOSER =
  REWRITE_TAC[NONOVERLAPPING_CLAUSES] THEN REPEAT CONJ_TAC THEN
  (NONOVERLAPPING_TAC ORELSE CONV_TAC WORD_REDUCE_CONV ORELSE CONV_TAC WORD_RULE);;
let SEAM_RECON =
  REWRITE_TAC[WORD_ADD_ASSOC_CONSTS; WORD_ADD_0] THEN
  CONV_TAC(DEPTH_CONV NUM_ADD_CONV) THEN ASM_REWRITE_TAC[];;

let mini_leg = match_leg MINI_i THEN sublem_a "s" "s'" THEN SEAM_RECON;;
let inner_leg =
  SUBGOAL_THEN bighyp_i ASSUME_TAC THENL
   [ INNER_HYP_CLOSER;
     match_leg INNER_i THEN sublem_a "s" "s'" THEN SEAM_RECON ];;

let HBSTEP =
  prove(`sha512_hash_blocks (m_fn:num->int64 list) [a;b;c;d;e;f;g;h] (i+1) =
         sha512_block (m_fn i)
           (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)`,
        REWRITE_TAC[sha512_hash_blocks]);;
let HBLIST =
  prove(`[EL 0 (sha512_hash_blocks (m_fn:num->int64 list) [a;b;c;d;e;f;g;h] i);
          EL 1 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 2 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 3 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 4 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 5 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 6 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i);
          EL 7 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i)] =
         sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] i`,
        MATCH_MP_TAC EL8_RECONSTRUCT THEN
        MATCH_MP_TAC LENGTH_SHA512_HASH_BLOCKS THEN
        REWRITE_TAC[LENGTH] THEN ARITH_TAC);;
let SB_GEN =
  prove(`!m hsh j. j < 8
         ==> EL j (sha512_block m hsh) =
             word_add (EL j (sha512_compress_rounds m hsh 80)) (EL j hsh)`,
        REWRITE_TAC[sha512_block] THEN REPEAT GEN_TAC THEN
        CONV_TAC(TOP_DEPTH_CONV let_CONV) THEN
        REWRITE_TAC[ARITH_RULE `j < 8 <=> j = 0 \/ j = 1 \/ j = 2 \/ j = 3 \/
                                j = 4 \/ j = 5 \/ j = 6 \/ j = 7`] THEN
        STRIP_TAC THEN ASM_REWRITE_TAC[] THEN
        CONV_TAC(ONCE_DEPTH_CONV EL_CONV) THEN REWRITE_TAC[]);;
let RSI_ADV = prove
 (`word_add (word_add (dataptr:int64) (word (128 * i))) (word 128) =
   word_add dataptr (word (128 * (i + 1)))`,
  SUBST1_TAC(ARITH_RULE `128 * (i + 1) = 128 * i + 128`) THEN
  CONV_TAC WORD_RULE);;
let taillp_reconcile =
  REWRITE_TAC[HBSTEP] THEN SIMP_TAC[SB_GEN; ARITH] THEN
  REWRITE_TAC[HBLIST] THEN
  REWRITE_TAC[RSI_ADV] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[RECON; RSI_ADV; HBLIST]) THEN
  REWRITE_TAC[RECON] THEN ASM_REWRITE_TAC[];;
let taillp_leg =
  match_leg TAILLP_i THEN sublem_a "s" "s'" THEN taillp_reconcile;;

let MSGREAD_ONE =
  W(fun (asl,w) ->
     let elapp = rand(rand w) in
     let jv = rand(rator elapp) in
     let iv2 = rand(rand elapp) in
     FIRST_X_ASSUM(fun th ->
        if is_forall(concl th) then MP_TAC(SPECL [iv2; jv] th) else NO_TAC) THEN
     ANTS_TAC THENL [ASM_ARITH_TAC; ALL_TAC] THEN
     DISCH_THEN(fun dth ->
        let gaddr = rand(rand(rand(rator(lhs w)))) in
        let daddr = rand(rand(rand(rator(lhs(concl dth))))) in
        SUBGOAL_THEN (mk_eq(gaddr, daddr))
          (fun aeq -> REWRITE_TAC[aeq] THEN ACCEPT_TAC dth)) THEN
     CONV_TAC WORD_RULE);;
let DERIVE_MSG_READS = REPEAT CONJ_TAC THEN MSGREAD_ONE;;

let compose_tac =
  ENSURES_SEQUENCE_TAC `pc + 0x6b` bodyQ6b THEN CONJ_TAC THENL
   [ mini_leg;
     ENSURES_SEQUENCE_TAC `pc + 0x1160` bodyQ1160 THEN CONJ_TAC THENL
      [ inner_leg; taillp_leg ] ];;

let body_ff_tac =
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT DISCH_TAC THEN
  MATCH_MP_TAC ENSURES_PRECONDITION_THM THEN
  W(fun (asl,w) ->
     let imp = lhand(body(rand w)) in
     let pprime = rator(lhand(snd(dest_forall imp))) in
     EXISTS_TAC (aug_of_prelam pprime)) THEN
  CONJ_TAC THENL
   [ GEN_TAC THEN REWRITE_TAC[] THEN
     DISCH_THEN(STRIP_ASSUME_TAC o CONV_RULE(TOP_DEPTH_CONV BETA_CONV)) THEN
     ASM_REWRITE_TAC[] THEN DERIVE_MSG_READS;
     compose_tac ];;

let SHA512_BLOCK_NOHW_BODY_FF = prove(ff_concl, body_ff_tac);;

(* ============================ assemble core CORRECT ===================== *)
let body_leg =
  REPEAT STRIP_TAC THEN
  MATCH_MP_TAC (REWRITE_RULE[SOME_FLAGS; IMP_IMP] SHA512_BLOCK_NOHW_BODY_FF) THEN
  ASM_REWRITE_TAC[] THEN TRY ASM_ARITH_TAC;;

let SHA512_COMPRESS_CORRECT = prove(correct_concl,
  REWRITE_TAC[SOME_FLAGS] THEN REPEAT GEN_TAC THEN REPEAT STRIP_TAC THEN
  ENSURES_SEQUENCE_TAC `pc + 0x61` q_top THEN CONJ_TAC THENL
   [ leg1;
     ENSURES_WHILE_PUP_TAC `num_blocks:num` `pc + 0x61` `pc + 0x11b8` invariant THEN
     REPEAT CONJ_TAC THENL
      [ ASM_ARITH_TAC;
        (ENSURES_INIT_TAC "s0" THEN ENSURES_FINAL_STATE_TAC THEN ASM_REWRITE_TAC[]);
        body_leg; leg_back; leg_exit ] ]);;

(* ======================================================================== *)
(* Phase 12 — SysV subroutine CORRECT (NOIBT + IBT).                         *)
(* Wraps the core SHA512_COMPRESS_CORRECT with the prologue/epilogue.        *)
(* The transpiler epilogue is NON-pop (recovers caller-SP from slot152 via   *)
(* `mov 152(%rsp),%rsi`, then 6 negative-offset reg restores + `lea (%rsi)`  *)
(* + ret), so we hand-assemble the wrapper using the keccak4-style dynamic    *)
(* and-rsp alignment-delta pattern rather than the canned                    *)
(* GEN_X86_ADD_RETURN_STACK_TAC.                                             *)
(*                                                                            *)
(* The data<->stack-frame nonoverlapping regions are 279 = 271-byte frame +   *)
(* the 8-byte return slot at entry-SP (cf. keccak4's `0x37f + 8`): the `ret`  *)
(* reads the return address at entry-SP (= stackpointer+271 after the +271    *)
(* offset shift), which sits just OUTSIDE the 271-byte frame, so STATE_UPDATE *)
(* needs RA-slot _|_ statep to carry the return address across the core       *)
(* BIGSTEP. Frame 271 = 48 (6 pushes) + 160 (sub 0xa0) + 63 (and-rsp slack).  *)
(* ======================================================================== *)

(* mc = APPEND [endbr64] (tmc (pc+4)), for the IBT lift via ADD_IBT_RULE ~bridge *)
let SHA512_COMPRESS_MC_BRIDGE = prove
 (`!pc kk. sha512_compress_mc pc kk =
     APPEND [word 0xf3:byte; word 0x0f; word 0x1e; word 0xfa]
            (sha512_compress_tmc (pc + 4) kk)`,
  REPEAT GEN_TAC THEN
  REWRITE_TAC[sha512_compress_mc;
              sha512_compress_tmc; APPEND] THEN
  REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
  REWRITE_TAC[INT_ARITH `(&pc + &4) + &107 = &pc + &111:int`] THEN
  REWRITE_TAC[]);;

let LEN_K512 = CONV_RULE (RAND_CONV LENGTH_CONV)
                 (AP_TERM `LENGTH:byte list->num` K512_DATA);;

let K_BYTES_FORM = prove
 (`bytes_loaded s (word kk:int64) K512 <=>
   read (memory :> bytes (word kk:int64,1312)) s = num_of_bytelist K512`,
  REWRITE_TAC[bytes_loaded; READ_BYTELIST_EQ_BYTES; LEN_K512]);;

let ra_fact = ref TRUTH;;

let SHA512_COMPRESS_NOIBT_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int64 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 0x6b) /\
   nonoverlapping (word pc,4578) (statep:int64,64) /\
   nonoverlapping (word pc,4578) (word_sub stackpointer (word 271):int64,279) /\
   nonoverlapping (word pc,4578) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (word pc,4578) (word kk:int64,1312) /\
   nonoverlapping (statep:int64,64) (word_sub stackpointer (word 271):int64,279) /\
   nonoverlapping (statep:int64,64) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (statep:int64,64) (word kk:int64,1312) /\
   nonoverlapping (word_sub stackpointer (word 271):int64,279) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 271):int64,279) (word kk:int64,1312) /\
   0 < num_blocks /\
   val (dataptr:int64) + 128 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha512_compress_tmc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes64 statep) s = (a:int64) /\
             read (memory :> bytes64 (word_add statep (word 8))) s = (b:int64) /\
             read (memory :> bytes64 (word_add statep (word 16))) s = (c:int64) /\
             read (memory :> bytes64 (word_add statep (word 24))) s = (d:int64) /\
             read (memory :> bytes64 (word_add statep (word 32))) s = (e:int64) /\
             read (memory :> bytes64 (word_add statep (word 40))) s = (f:int64) /\
             read (memory :> bytes64 (word_add statep (word 48))) s = (g:int64) /\
             read (memory :> bytes64 (word_add statep (word 56))) s = (h:int64) /\
             bytes_loaded s (word kk) K512 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes64
                           (word_add dataptr (word (128*i' + 8*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int64)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes64 statep) s =
               EL 0 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 8))) s =
               EL 1 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 16))) s =
               EL 2 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 24))) s =
               EL 3 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 32))) s =
               EL 4 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 40))) s =
               EL 5 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 48))) s =
               EL 6 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 56))) s =
               EL 7 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes64 statep;
                    memory :> bytes64 (word_add statep (word 8));
                    memory :> bytes64 (word_add statep (word 16));
                    memory :> bytes64 (word_add statep (word 24));
                    memory :> bytes64 (word_add statep (word 32));
                    memory :> bytes64 (word_add statep (word 40));
                    memory :> bytes64 (word_add statep (word 48));
                    memory :> bytes64 (word_add statep (word 56))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 271),271)])`,
  REWRITE_TAC[MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI; C_ARGUMENTS;
              fst SHA512_COMPRESS_EXEC] THEN
  REPLICATE_TAC 14 GEN_TAC THEN
  WORD_FORALL_OFFSET_TAC 271 THEN
  REWRITE_TAC[K_BYTES_FORM] THEN
  REPEAT STRIP_TAC THEN
  ENSURES_PRESERVED_TAC "rbx_init" `RBX` THEN
  ENSURES_PRESERVED_TAC "rbp_init" `RBP` THEN
  ENSURES_PRESERVED_TAC "r12_init" `R12` THEN
  ENSURES_PRESERVED_TAC "r13_init" `R13` THEN
  ENSURES_PRESERVED_TAC "r14_init" `R14` THEN
  ENSURES_PRESERVED_TAC "r15_init" `R15` THEN
  ENSURES_INIT_TAC "s0" THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (1--11) THEN
  (* capture the s11 return-address fact into a ref (runs at proof time) *)
  W(fun (asl,w) ->
     let isra (_,th) =
       let c = concl th in
       (try let _ = find_term (fun t -> try fst(dest_var t)="returnaddress"
                                        with _->false) c in is_eq c
        with _->false) in
     ra_fact := snd (List.find isra asl); ALL_TAC) THEN
  ABBREV_TAC
   `delta =
    val(word_sub (word 63)
                 (word_and (word_add stackpointer (word 63)) (word 63)):int64)` THEN
  SUBGOAL_THEN `delta <= 63` ASSUME_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `word_and (word_add stackpointer (word 63)) (word 18446744073709551552):int64 =
    word_add stackpointer (word delta)`
  SUBST_ALL_TAC THENL
   [EXPAND_TAC "delta" THEN CONV_TAC BITBLAST_RULE; ALL_TAC] THEN
  SUBGOAL_THEN
   `8 * val (word_shl (word num_blocks:int64) 4) = 128 * num_blocks`
  ASSUME_TAC THENL
   [REWRITE_TAC[VAL_WORD_SHL; VAL_WORD; DIMINDEX_64] THEN
    REWRITE_TAC[ARITH_RULE `2 EXP 4 = 16`] THEN
    SUBGOAL_THEN `num_blocks MOD 2 EXP 64 = num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 128 * n < 2 EXP 64 ==> n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    SUBGOAL_THEN `(16 * num_blocks) MOD 2 EXP 64 = 16 * num_blocks` SUBST1_TAC THENL
     [MATCH_MP_TAC MOD_LT THEN
      MATCH_MP_TAC(ARITH_RULE `val(dataptr:int64) + 128 * n < 2 EXP 64 ==> 16 * n < 2 EXP 64`) THEN
      ASM_REWRITE_TAC[]; ALL_TAC] THEN
    ARITH_TAC; ALL_TAC] THEN
  RULE_ASSUM_TAC(REWRITE_RULE[ASSUME
    `8 * val (word_shl (word num_blocks:int64) 4) = 128 * num_blocks`]) THEN
  SUBGOAL_THEN
   `read (memory :> bytelist (word kk:int64,LENGTH K512)) s11 = K512`
  ASSUME_TAC THENL
   [REWRITE_TAC[READ_BYTELIST_EQ_BYTES; LEN_K512] THEN ASM_REWRITE_TAC[]; ALL_TAC] THEN
  MP_TAC(REWRITE_RULE[IMP_IMP] (SPECL
   [`pc:num`; `kk:num`; `word_add stackpointer (word delta):int64`;
    `statep:int64`; `dataptr:int64`;
    `word_add dataptr (word (128*num_blocks)):int64`;
    `word_add stackpointer (word 271):int64`; `num_blocks:num`;
    `a:int64`;`b:int64`;`c:int64`;`d:int64`;`e:int64`;`f:int64`;`g:int64`;`h:int64`;
    `m_fn:num->int64 list`]
   SHA512_COMPRESS_CORRECT)) THEN
  ANTS_TAC THENL
   [REPEAT CONJ_TAC THEN
    (NONOVERLAPPING_TAC ORELSE ASM_REWRITE_TAC[]); ALL_TAC] THEN
  REWRITE_TAC[SOME_FLAGS] THEN
  X86_BIGSTEP_TAC SHA512_COMPRESS_EXEC "s12" THEN
  ABBREV_TAC `asp:int64 = word_add stackpointer (word delta)` THEN
  (* re-derive the return-address fact at s12 across the core frame. The deref
     of ra_fact is DEFERRED to proof time via W(...) (an eager ASSUME_TAC(!ra_fact)
     would bake in TRUTH). With the 279-widened hyps, STATE_UPDATE_RULE proves
     RA-slot _|_ statep so the fact carries. *)
  SUBGOAL_THEN
   `read (memory :> bytes64 (word_add stackpointer (word 271))) s12 = returnaddress`
  ASSUME_TAC THENL
   [W(fun (asl,w) -> ASSUME_TAC(!ra_fact)) THEN
    FIRST_X_ASSUM(MP_TAC o check (maychange_term o concl)) THEN
    REWRITE_TAC[MAYCHANGE; SEQ_ID] THEN
    REWRITE_TAC[GSYM SEQ_ASSOC] THEN
    PURE_REWRITE_TAC[ASSIGNS_SEQ] THEN
    CONV_TAC (TOP_DEPTH_CONV BETA_CONV) THEN
    REWRITE_TAC[ASSIGNS_THM] THEN
    REWRITE_TAC[LEFT_IMP_EXISTS_THM] THEN REPEAT GEN_TAC THEN
    ASSUMPTION_STATE_UPDATE_TAC THEN
    DISCH_THEN(K ALL_TAC) THEN
    ASM_REWRITE_TAC[]; ALL_TAC] THEN
  X86_STEPS_TAC SHA512_COMPRESS_EXEC (13--21) THEN
  (* undo the asp abbreviation in the asms so CONTAINED_TAC in the frame
     subsumption can relate the asp-keyed writes to stackpointer (delta<=63). *)
  RULE_ASSUM_TAC(REWRITE_RULE[SYM(ASSUME
     `word_add stackpointer (word delta):int64 = asp`)]) THEN
  ENSURES_FINAL_STATE_TAC THEN
  REPEAT CONJ_TAC THEN
  TRY MONOTONE_MAYCHANGE_TAC THEN
  ASM_REWRITE_TAC[] THEN
  TRY(CONV_TAC WORD_RULE));;

let SHA512_COMPRESS_SUBROUTINE_CORRECT = prove
 (`!pc kk statep dataptr (num_blocks:num)
    a b c d e f g h (m_fn:num->int64 list) stackpointer returnaddress.
   riprel32_within_bounds kk (pc + 0x6f) /\
   nonoverlapping (word pc,4582) (statep:int64,64) /\
   nonoverlapping (word pc,4582) (word_sub stackpointer (word 271):int64,279) /\
   nonoverlapping (word pc,4582) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (word pc,4582) (word kk:int64,1312) /\
   nonoverlapping (statep:int64,64) (word_sub stackpointer (word 271):int64,279) /\
   nonoverlapping (statep:int64,64) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (statep:int64,64) (word kk:int64,1312) /\
   nonoverlapping (word_sub stackpointer (word 271):int64,279) (dataptr:int64,128*num_blocks) /\
   nonoverlapping (word_sub stackpointer (word 271):int64,279) (word kk:int64,1312) /\
   0 < num_blocks /\
   val (dataptr:int64) + 128 * num_blocks < 2 EXP 64
   ==> ensures x86
        (\s. bytes_loaded s (word pc) (sha512_compress_mc pc kk) /\
             read RIP s = word pc /\
             read RSP s = stackpointer /\
             read (memory :> bytes64 stackpointer) s = returnaddress /\
             C_ARGUMENTS [statep; dataptr; word num_blocks] s /\
             read (memory :> bytes64 statep) s = (a:int64) /\
             read (memory :> bytes64 (word_add statep (word 8))) s = (b:int64) /\
             read (memory :> bytes64 (word_add statep (word 16))) s = (c:int64) /\
             read (memory :> bytes64 (word_add statep (word 24))) s = (d:int64) /\
             read (memory :> bytes64 (word_add statep (word 32))) s = (e:int64) /\
             read (memory :> bytes64 (word_add statep (word 40))) s = (f:int64) /\
             read (memory :> bytes64 (word_add statep (word 48))) s = (g:int64) /\
             read (memory :> bytes64 (word_add statep (word 56))) s = (h:int64) /\
             bytes_loaded s (word kk) K512 /\
             (!i' j. i' < num_blocks /\ j < 16
                     ==> read (memory :> bytes64
                           (word_add dataptr (word (128*i' + 8*j)))) s =
                         word_bytereverse (EL j (m_fn i'):int64)))
        (\s. read RIP s = returnaddress /\
             read RSP s = word_add stackpointer (word 8) /\
             read (memory :> bytes64 statep) s =
               EL 0 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 8))) s =
               EL 1 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 16))) s =
               EL 2 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 24))) s =
               EL 3 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 32))) s =
               EL 4 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 40))) s =
               EL 5 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 48))) s =
               EL 6 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks) /\
             read (memory :> bytes64 (word_add statep (word 56))) s =
               EL 7 (sha512_hash_blocks m_fn [a;b;c;d;e;f;g;h] num_blocks))
        (MAYCHANGE [RSP] ,, MAYCHANGE_REGS_AND_FLAGS_PERMITTED_BY_ABI ,,
         MAYCHANGE [memory :> bytes64 statep;
                    memory :> bytes64 (word_add statep (word 8));
                    memory :> bytes64 (word_add statep (word 16));
                    memory :> bytes64 (word_add statep (word 24));
                    memory :> bytes64 (word_add statep (word 32));
                    memory :> bytes64 (word_add statep (word 40));
                    memory :> bytes64 (word_add statep (word 48));
                    memory :> bytes64 (word_add statep (word 56))] ,,
         MAYCHANGE [memory :> bytes (word_sub stackpointer (word 271),271)])`,
  MATCH_ACCEPT_TAC(ADD_IBT_RULE
    ~bridge:(Some SHA512_COMPRESS_MC_BRIDGE)
    SHA512_COMPRESS_NOIBT_SUBROUTINE_CORRECT));;

(* ========================================================================= *)
(* Phase 13 — Windows ABI variant: freeze + decomposition infrastructure.    *)
(*                                                                           *)
(* Windows mc/tmc/EXEC for sha512_compress, from the .obj.                   *)
(* Inline-shim model: endbr(4) + shim(11: push rdi;push rsi;mov rdi,rcx;     *)
(* mov rsi,rdx;mov rdx,r8) + byte-identical SysV body + divergent epilogue   *)
(* (pop rsi; pop rdi before ret). Constant named K512W to avoid clashing     *)
(* with the already-defined K512 byte-list. (Wrappers proper + the bl_tmc    *)
(* proof chain are added in a later commit once this infra is in place.)     *)
(* ========================================================================= *)

