let sha512_compress_windows_tmc =
  define_trimmed "sha512_compress_windows_tmc"
                 sha512_compress_windows_mc;;

let SHA512_WIN_EXEC = X86_MK_EXEC_RULE sha512_compress_windows_tmc;;

(* ======================================================================== *)
(* Phase 13 — Windows subroutine CORRECT: shared infrastructure.            *)
(*                                                                          *)
(* The Windows .obj is the INLINE-SHIM model: its trimmed machine code is   *)
(*   windows_tmc pc kk = shim(11) ++ COMMON(4577) ++ [pop rsi; pop rdi; ret]*)
(* where shim(11) = push rdi; push rsi; mov rdi,rcx; mov rsi,rdx; mov rdx,r8*)
(* and COMMON is byte-identical to BUTLAST(sysv_tmc) modulo the riprel LEA-  *)
(* K512 displacement, which shifts by the 11-byte shim ((&pc+11)+107 =       *)
(* &pc+118; the tmc offset is 107, the un-trimmed mc is +111). The SysV tmc  *)
(* = COMMON ++ [ret]; the Windows image lacks the                            *)
(* SysV trailing `ret` (it has `pop rsi` there), so ONLY BUTLAST(sysv_tmc)   *)
(* is a subprogram of windows_tmc (at offset 11). The canned                 *)
(* WINDOWS_X86_WRAP_STACK_TAC and BYTES_LOADED_SUBPROGRAM_RULE do not apply  *)
(* (they need concrete byte lists; our reloc-mc carries the symbolic riprel  *)
(* atom), so we hand-roll the wrapper.                                       *)
(* ======================================================================== *)

(* 11-byte ABI shim prefix and 3-byte non-pop epilogue tail (byte-identical  *)
(* to SHA-256: 0x57;0x56;0x48;0x89;0xcf;0x48;0x89;0xd6;0x4c;0x89;0xc2 /       *)
(*  pop rsi; pop rdi; ret = words 94;95;195).                                *)
let WIN_SHIM11_512 = `[word 0x57; word 0x56; word 0x48; word 0x89; word 0xcf;
   word 0x48; word 0x89; word 0xd6; word 0x4c; word 0x89; word 0xc2]:byte list`;;
let WIN_TAIL3_512  = `[word 94; word 95; word 195]:byte list`;;

(* riprel: SysV TMC uses &K512-(&pc+107) (un-trimmed mc is +111; endbr trim    *)
(* removes 4); the 11-byte shim shifts the TMC offset by 11: 107 -> 118.       *)
let SHA512_WIN_RIPREL_ALIGN = INT_ARITH `(&pc + &11) + &107:int = &pc + &118`;;

(* WIN_DECOMP: windows_tmc = shim ++ BUTLAST(sysv_tmc @ pc+11) ++ tail.       *)
let SHA512_WIN_DECOMP =
  let appf = `APPEND:byte list->byte list->byte list` in
  let butl = `BUTLAST (sha512_compress_tmc (pc+11) kk)` in
  let rhs_tm = mk_comb(mk_comb(appf, WIN_SHIM11_512),
                mk_comb(mk_comb(appf, butl), WIN_TAIL3_512)) in
  prove
   (mk_eq(`sha512_compress_windows_tmc pc kk`, rhs_tm),
    REWRITE_TAC[sha512_compress_windows_tmc;
                sha512_compress_tmc] THEN
    REWRITE_TAC[BUTLAST_CLAUSES; APPEND] THEN
    REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
    REWRITE_TAC[SHA512_WIN_RIPREL_ALIGN] THEN REWRITE_TAC[]);;

(* WIN_BODY_BRIDGE: the windows->sysv-body bytes_loaded bridge.               *)
let SHA512_WIN_BODY_BRIDGE = prove
 (`bytes_loaded s (word pc) (sha512_compress_windows_tmc pc kk)
   ==> bytes_loaded s (word (pc + 11))
          (BUTLAST (sha512_compress_tmc (pc + 11) kk))`,
  REWRITE_TAC[SHA512_WIN_DECOMP; bytes_loaded_append; LENGTH] THEN
  CONV_TAC NUM_REDUCE_CONV THEN
  REWRITE_TAC[GSYM WORD_ADD; WORD_ADD_0] THEN
  REWRITE_TAC[ARITH_RULE `pc + 11 = 11 + pc`] THEN
  STRIP_TAC THEN ASM_REWRITE_TAC[]);;

(* bl_tmc: the BUTLAST core program + its EXEC (decode rows [0,4577)).        *)
(* X86_MK_EXEC on BUTLAST of the reloc tmc fails via AP_TERM (X86_TRIM_EXEC), *)
(* so we name the reduced BUTLAST list as its own constant and MK_EXEC that.  *)
let sha512_compress_bl_tmc = new_definition
 `sha512_compress_bl_tmc pc kk =
    BUTLAST (sha512_compress_tmc pc kk)`;;

let SHA512_BL_TMC_RED =
  REWRITE_RULE[sha512_compress_tmc; BUTLAST_CLAUSES]
    (SPEC_ALL sha512_compress_bl_tmc);;

let SHA512_BL_EXEC = X86_MK_EXEC_RULE SHA512_BL_TMC_RED;;

(* WINDOWS_MC_BRIDGE: windows_mc = [endbr] ++ windows_tmc(pc+4), for IBT.     *)
(* The windows mc trims the 4-byte endbr; the riprel offset in the windows mc *)
(* is pc+122 (=118+4) vs pc+118 in the tmc, realigned by (&pc+4)+118=&pc+122. *)
let SHA512_COMPRESS_WINDOWS_MC_BRIDGE = prove
 (`!pc kk. sha512_compress_windows_mc pc kk =
     APPEND [word 0xf3:byte; word 0x0f; word 0x1e; word 0xfa]
            (sha512_compress_windows_tmc (pc + 4) kk)`,
  REPEAT GEN_TAC THEN
  REWRITE_TAC[sha512_compress_windows_mc;
              sha512_compress_windows_tmc; APPEND] THEN
  REWRITE_TAC[GSYM INT_OF_NUM_ADD] THEN
  REWRITE_TAC[INT_ARITH `(&pc + &4) + &118 = &pc + &122:int`] THEN
  REWRITE_TAC[]);;


