(* Phase 13b (session-016): bl_tmc cone re-proof.  The committed SysV core   *)
(* CORRECT is over the FULL sysv_tmc; the Windows image embeds only          *)
(* BUTLAST(sysv_tmc), and full=>BUTLAST is the UNSOUND weakening.  So the     *)
(* ENTIRE core cone is RE-STATED over sha512_compress_bl_tmc and RE-PROVED    *)
(* by replaying each committed tactic VERBATIM with SHA512_COMPRESS_EXEC ->   *)
(* SHA512_BL_EXEC.  bl_tmc decodes identically for rows [0,4577) so every     *)
(* stepped/cut-point tactic closes verbatim.  (int64 clone of the SHA-256     *)
(* bl_tmc cone, ragamuffin_sha256_x86_nohw L9342-11827.)                      *)
(* ======================================================================== *)

(* statement surgery: full sysv_tmc -> bl_tmc, length 4578 -> 4577. *)
let bl_of_stmt tm =
  subst [`4577`,`4578`]
   (subst [`sha512_compress_bl_tmc`,
           `sha512_compress_tmc`] tm);;

